130	static inline int expirySamplingShouldSkipDict(dict *d, int didx) {
131	    long long numkeys = dictSize(d);
132	    unsigned long buckets = dictBuckets(d);
133	    /* When there are less than 1% filled buckets, sampling the key
134	     * space is expensive, so stop here waiting for better times...
135	     * The dictionary will be resized asap. */
136	    if (buckets > DICT_HT_INITIAL_SIZE && (numkeys * 100/buckets < 1)) {
137	        return 1;
138	    }
139	
140	    /* During atomic slot migration, keys that are being imported are in an
141	     * intermediate state. we cannot expire them and therefore skip them. */
142	    if (!clusterCanAccessKeysInSlot(didx)) return 1;
143	
144	    return 0;
145	}
