147	/* SubexpireCtx passed to activeSubexpiresCb() */
148	typedef struct SubexpireCtx {
149	    uint32_t fieldsToExpireQuota;
150	    redisDb *db;
151	    int slot;
152	} SubexpireCtx;
153	
154	/*
155	 * Active sub-expiration callback
156	 *
157	 * Called by activeSubexpires() for each key registered in the subexpires DB
158	 * with an expiration-time on its "elements"  that are less than or equal current
159	 * time.
160	 *
161	 * This callback performs the following actions for each hash:
162	 * - Delete expired fields as by calling ebExpire(hash)
163	 * - If afterward there are future fields to expire, it will update the hash in
164	 *   HFE DB with the next hash-field minimum expiration time by returning
165	 *   ACT_UPDATE_EXP_ITEM.
166	 * - If the hash has no more fields to expire, it is removed from the HFE DB
167	 *   by returning ACT_REMOVE_EXP_ITEM.
168	 * - If hash has no more fields afterward, it will remove the hash from keyspace.
169	 */
170	static ExpireAction activeSubexpiresCb(eItem item, void *ctx) {
171	    SubexpireCtx *subexCtx = ctx;
172	
173	    /* If no more quota left for this callback, stop */
174	    if (subexCtx->fieldsToExpireQuota == 0)
175	        return ACT_STOP_ACTIVE_EXP;
176	
177	    kvobj *kv = (kvobj *) item;
178	
179	    /* currently we only support hash type sub-expire */
180	    assert(kv->type == OBJ_HASH);
181	    uint64_t nextExpTime = hashTypeExpire(subexCtx->db, kv, &subexCtx->fieldsToExpireQuota, 0, 1);
182	
183	    /* If hash has no more fields to expire or got deleted, indicate
184	     * to remove it from HFE DB to the caller ebExpire() */
185	    if (nextExpTime == EB_EXPIRE_TIME_INVALID || nextExpTime == 0) {
186	        return ACT_REMOVE_EXP_ITEM;
187	    } else {
188	        /* Hash has more fields to expire. Update next expiration time of the hash
189	         * and indicate to add it back to global HFE DS */
190	        ebSetMetaExpTime(hashGetExpireMeta(item), nextExpTime);
191	        return ACT_UPDATE_EXP_ITEM;
192	    }
193	}
