195	/* DB active expire and update hashes with time-expiration on fields.
196	 *
197	 * The callback function activeSubexpiresCb() is invoked for each hash registered
198	 * in the subexpires DB with an expiration-time less than or equal to the
199	 * current time. This callback performs the following actions for each hash:
200	 * - If the hash has one or more fields to expire, it will delete those fields.
201	 * - If there are more fields to expire, it will update the hash with the next
202	 *   expiration time in subexpires DB.
203	 * - If the hash has no more fields to expire, it is removed from the subexpires DB.
204	 * - If the hash has no more fields, it is removed from the main DB.
205	 *
206	 * Returns number of fields active-expired.
207	 */
208	uint64_t activeSubexpires(redisDb *db, int slot, uint32_t maxFieldsToExpire) {
209	    SubexpireCtx ctx = { .db = db, .fieldsToExpireQuota = maxFieldsToExpire, .slot = slot };
210	    ExpireInfo info = {
211	            .maxToExpire = UINT64_MAX, /* Only maxFieldsToExpire play a role */
212	            .onExpireItem = activeSubexpiresCb,
213	            .ctx = &ctx,
214	            .now = commandTimeSnapshot(),
215	            .itemsExpired = 0};
216	
217	    estoreActiveExpire(db->subexpires, slot, &info);
218	
219	    /* Return number of fields active-expired */
220	    return maxFieldsToExpire - ctx.fieldsToExpireQuota;
221	}
