223	/* Active expiration Cycle for hash-fields.
224	 *
225	 * Note that releasing fields is expected to be more predictable and rewarding
226	 * than releasing keys because it is stored in `ebuckets` DS which optimized for
227	 * active expiration and in addition the deletion of fields is simple to handle. */
228	static inline void activeSubexpiresCycle(int type) {
229	    /* Remember current db across calls */
230	    static unsigned int currentDb = 0;
231	    static int currentSlot = -1;
232	
233	    /* Tracks the count of fields actively expired for the current database.
234	     * This count continues as long as it fails to actively expire all expired
235	     * fields of currentDb, indicating a possible need to adjust the value of
236	     * maxToExpire. */
237	    static uint64_t activeExpirySequence = 0;
238	    /* Threshold for adjusting maxToExpire */
239	    const uint32_t EXPIRED_FIELDS_TH = 1000000;
240	
241	    redisDb *db = server.db + currentDb;
242	
243	    /* If db is empty, move to next db and return */
244	    if (estoreIsEmpty(db->subexpires)) {
245	        activeExpirySequence = 0;
246	        currentDb = (currentDb + 1) % server.dbnum;
247	        return;
248	    }
249	    if (currentSlot == -1)
250	        currentSlot = estoreGetFirstNonEmptyBucket(db->subexpires);
251	
252	    /* During atomic slot migration, keys that are being imported are in an
253	     * intermediate state. We cannot expire them and therefore skip them. */
254	    if (!clusterCanAccessKeysInSlot(currentSlot)) {
255	        /* Move to next non-empty subexpires slot */
256	        currentSlot = estoreGetNextNonEmptyBucket(db->subexpires, currentSlot);
257	        if (currentSlot == -1)
258	            currentDb = (currentDb + 1) % server.dbnum; /* Move to next db */
259	        return;
260	    }
261	
262	    /* Maximum number of fields to actively expire on a single call */
263	    uint32_t maxToExpire = HFE_DB_BASE_ACTIVE_EXPIRE_FIELDS_PER_SEC / server.hz;
264	
265	    /* If running for a while and didn't manage to active-expire all expired fields of
266	     * currentDb (i.e. activeExpirySequence becomes significant) then adjust maxToExpire */
267	    if ((activeExpirySequence > EXPIRED_FIELDS_TH) && (type == ACTIVE_EXPIRE_CYCLE_SLOW)) {
268	        /* maxToExpire is multiplied by a factor between 1 and 32, proportional to
269	         * the number of times activeExpirySequence exceeded EXPIRED_FIELDS_TH */
270	        uint64_t factor = activeExpirySequence / EXPIRED_FIELDS_TH;
271	        maxToExpire *= (factor<32) ? factor : 32;
272	    }
273	
274	    if (activeSubexpires(db, currentSlot, maxToExpire) == maxToExpire) {
275	        /* active-expire reached maxToExpire limit */
276	        activeExpirySequence += maxToExpire;
277	    } else {
278	        /* Managed to active-expire all expired fields of currentDb */
279	        activeExpirySequence = 0;
280	        /* Move to next non-empty subexpires slot */
281	        currentSlot = estoreGetNextNonEmptyBucket(db->subexpires, currentSlot);
282	        if (currentSlot == -1)
283	            currentDb = (currentDb + 1) % server.dbnum;
284	    }
285	}
286	
287	void activeExpireCycle(int type) {
288	    /* Adjust the running parameters according to the configured expire
289	     * effort. The default effort is 1, and the maximum configurable effort
290	     * is 10. */
291	    unsigned long
292	    effort = server.active_expire_effort-1, /* Rescale from 0 to 9. */
293	    config_keys_per_loop = ACTIVE_EXPIRE_CYCLE_KEYS_PER_LOOP +
294	                           ACTIVE_EXPIRE_CYCLE_KEYS_PER_LOOP/4*effort,
295	    config_cycle_fast_duration = ACTIVE_EXPIRE_CYCLE_FAST_DURATION +
296	                                 ACTIVE_EXPIRE_CYCLE_FAST_DURATION/4*effort,
297	    config_cycle_slow_time_perc = ACTIVE_EXPIRE_CYCLE_SLOW_TIME_PERC +
298	                                  2*effort,
299	    config_cycle_acceptable_stale = ACTIVE_EXPIRE_CYCLE_ACCEPTABLE_STALE-
300	                                    effort;
301	
302	    /* This function has some global state in order to continue the work
303	     * incrementally across calls. */
304	    static unsigned int current_db = 0; /* Next DB to test. */
305	    static int timelimit_exit = 0;      /* Time limit hit in previous call? */
306	    static long long last_fast_cycle = 0; /* When last fast cycle ran. */
307	
308	    int j, iteration = 0;
309	    int dbs_per_call = CRON_DBS_PER_CALL;
310	    int dbs_performed = 0;
311	    long long start = ustime(), timelimit, elapsed;
312	
313	    /* If 'expire' action is paused, for whatever reason, then don't expire any key.
314	     * Typically, at the end of the pause we will properly expire the key OR we
315	     * will have failed over and the new primary will send us the expire. */
316	    if (isPausedActionsWithUpdate(PAUSE_ACTION_EXPIRE)) return;
317	
318	    if (type == ACTIVE_EXPIRE_CYCLE_FAST) {
319	        /* Don't start a fast cycle if the previous cycle did not exit
320	         * for time limit, unless the percentage of estimated stale keys is
321	         * too high. Also never repeat a fast cycle for the same period
322	         * as the fast cycle total duration itself. */
323	        if (!timelimit_exit &&
324	            server.stat_expired_stale_perc < config_cycle_acceptable_stale)
325	            return;
326	
327	        if (start < last_fast_cycle + (long long)config_cycle_fast_duration*2)
328	            return;
329	
330	        last_fast_cycle = start;
331	    }
332	
333	    /* We usually should test CRON_DBS_PER_CALL per iteration, with
334	     * two exceptions:
335	     *
336	     * 1) Don't test more DBs than we have.
337	     * 2) If last time we hit the time limit, we want to scan all DBs
338	     * in this iteration, as there is work to do in some DB and we don't want
339	     * expired keys to use memory for too much time. */
340	    if (dbs_per_call > server.dbnum || timelimit_exit)
341	        dbs_per_call = server.dbnum;
342	
343	    /* We can use at max 'config_cycle_slow_time_perc' percentage of CPU
344	     * time per iteration. Since this function gets called with a frequency of
345	     * server.hz times per second, the following is the max amount of
346	     * microseconds we can spend in this function. */
347	    timelimit = config_cycle_slow_time_perc*1000000/server.hz/100;
348	    timelimit_exit = 0;
349	    if (timelimit <= 0) timelimit = 1;
350	
351	    if (type == ACTIVE_EXPIRE_CYCLE_FAST)
352	        timelimit = config_cycle_fast_duration; /* in microseconds. */
353	
354	    /* Accumulate some global stats as we expire keys, to have some idea
355	     * about the number of keys that are already logically expired, but still
356	     * existing inside the database. */
357	    long total_sampled = 0;
358	    long total_expired = 0;
359	
360	    /* Try to smoke-out bugs (server.also_propagate should be empty here) */
361	    serverAssert(server.also_propagate.numops == 0);
362	
363	    /* Stop iteration when one of the following conditions is met:
364	     *
365	     * 1) We have checked a sufficient number of databases with expiration time.
366	     * 2) The time limit has been exceeded.
367	     * 3) All databases have been traversed. */
368	    for (j = 0; dbs_performed < dbs_per_call && timelimit_exit == 0 && j < server.dbnum; j++) {
369	        /* Scan callback data including expired and checked count per iteration. */
370	        expireScanData data;
371	        data.ttl_sum = 0;
372	        data.ttl_samples = 0;
373	
374	        redisDb *db = server.db+(current_db % server.dbnum);
375	        data.db = db;
376	
377	        int db_done = 0; /* The scan of the current DB is done? */
378	        int update_avg_ttl_times = 0, repeat = 0;
379	
380	        /* Increment the DB now so we are sure if we run out of time
381	         * in the current DB we'll restart from the next. This allows to
382	         * distribute the time evenly across DBs. */
383	        current_db++;
384	
385	        /* Interleaving sub-expiration with key expiration. Better call it before
386	         * handling expired keys because ebuckets is optimized for active expiration */
387	        activeSubexpiresCycle(type);
388	
389	        if (kvstoreSize(db->expires))
390	            dbs_performed++;
391	
392	        /* Continue to expire if at the end of the cycle there are still
393	         * a big percentage of keys to expire, compared to the number of keys
394	         * we scanned. The percentage, stored in config_cycle_acceptable_stale
395	         * is not fixed, but depends on the Redis configured "expire effort". */
396	        do {
397	            unsigned long num;
398	            iteration++;
399

400	            /* If there is nothing to expire try next DB ASAP. */
401	            if ((num = kvstoreSize(db->expires)) == 0) {
402	                db->avg_ttl = 0;
403	                break;
404	            }
405	            data.now = mstime();
406	
407	            /* The main collection cycle. Scan through keys among keys
408	             * with an expire set, checking for expired ones. */
409	            data.sampled = 0;
410	            data.expired = 0;
411	
412	            if (num > config_keys_per_loop)
413	                num = config_keys_per_loop;
414	
415	            /* Here we access the low level representation of the hash table
416	             * for speed concerns: this makes this code coupled with dict.c,
417	             * but it hardly changed in ten years.
418	             *
419	             * Note that certain places of the hash table may be empty,
420	             * so we want also a stop condition about the number of
421	             * buckets that we scanned. However scanning for free buckets
422	             * is very fast: we are in the cache line scanning a sequential
423	             * array of NULL pointers, so we can scan a lot more buckets
424	             * than keys in the same time. */
425	            long max_buckets = num*20;
426	            long checked_buckets = 0;
427	
428	            int origin_ttl_samples = data.ttl_samples;
429	
430	            while (data.sampled < num && checked_buckets < max_buckets) {
431	                db->expires_cursor = kvstoreScan(db->expires, db->expires_cursor, -1, expireScanCallback, expirySamplingShouldSkipDict, &data);
432	                if (db->expires_cursor == 0) {
433	                    db_done = 1;
434	                    break;
435	                }
436	                checked_buckets++;
437	            }
438	            total_expired += data.expired;
439	            total_sampled += data.sampled;
440	
441	            /* If find keys with ttl not yet expired, we need to update the average TTL stats once. */
442	            if (data.ttl_samples - origin_ttl_samples > 0) update_avg_ttl_times++;
443	
444	            /* We don't repeat the cycle for the current database if the db is done
445	             * for scanning or an acceptable number of stale keys (logically expired
446	             * but yet not reclaimed). */
447	            repeat = db_done ? 0 : (data.sampled == 0 || (data.expired * 100 / data.sampled) > config_cycle_acceptable_stale);
448	
449	            /* We can't block forever here even if there are many keys to
450	             * expire. So after a given amount of microseconds return to the
451	             * caller waiting for the other active expire cycle. */
452	            if ((iteration & 0xf) == 0 || !repeat) { /* Update the average TTL stats every 16 iterations or about to exit. */
453	                /* Update the average TTL stats for this database, 
454	                 * because this may reach the time limit. */
455	                if (data.ttl_samples) {
456	                    long long avg_ttl = data.ttl_sum / data.ttl_samples;
457	
458	                    /* Do a simple running average with a few samples.
459	                     * We just use the current estimate with a weight of 2%
460	                     * and the previous estimate with a weight of 98%. */
461	                    if (db->avg_ttl == 0) {
462	                        db->avg_ttl = avg_ttl;
463	                    } else {
464	                        /* The origin code is as follow.
465	                         * for (int i = 0; i < update_avg_ttl_times; i++) {
466	                         *   db->avg_ttl = (db->avg_ttl/50)*49 + (avg_ttl/50);
467	                         * } 
468	                         * We can convert the loop into a sum of a geometric progression.
469	                         * db->avg_ttl = db->avg_ttl * pow(0.98, update_avg_ttl_times) + 
470	                         *                  avg_ttl / 50 * (pow(0.98, update_avg_ttl_times - 1) + ... + 1) 
471	                         *             = db->avg_ttl * pow(0.98, update_avg_ttl_times) + 
472	                         *                  avg_ttl * (1 - pow(0.98, update_avg_ttl_times))
473	                         *             = avg_ttl +  (db->avg_ttl - avg_ttl) * pow(0.98, update_avg_ttl_times) 
474	                         * Notice that update_avg_ttl_times is between 1 and 16, we use a constant table 
475	                         * to accelerate the calculation of pow(0.98, update_avg_ttl_times).*/
476	                        db->avg_ttl = avg_ttl + (db->avg_ttl - avg_ttl) * avg_ttl_factor[update_avg_ttl_times - 1] ;
477	                    }
478	                    update_avg_ttl_times = 0;
479	                    data.ttl_sum = 0;
480	                    data.ttl_samples = 0;
481	                }
482	                if ((iteration & 0xf) == 0) { /* check time limit every 16 iterations. */
483	                    elapsed = ustime()-start;
484	                    if (elapsed > timelimit) {
485	                        timelimit_exit = 1;
486	                        server.stat_expired_time_cap_reached_count++;
487	                        break;
488	                    }
489	                }
490	            }
491	        } while (repeat);
492	    }
493	
494	    elapsed = ustime()-start;
495	    server.stat_expire_cycle_time_used += elapsed;
496	    latencyAddSampleIfNeeded("expire-cycle",elapsed/1000);
497	
498	    /* Update our estimate of keys existing but yet to be expired.
499	     * Running average with this sample accounting for 5%. */
500	    double current_perc;
501	    if (total_sampled) {
502	        current_perc = (double)total_expired/total_sampled;
503	    } else
504	        current_perc = 0;
505	    server.stat_expired_stale_perc = (current_perc*0.05)+
506	                                     (server.stat_expired_stale_perc*0.95);
507	}
