509	/*-----------------------------------------------------------------------------
510	 * Expires of keys created in writable slaves
511	 *
512	 * Normally slaves do not process expires: they wait the masters to synthesize
513	 * DEL operations in order to retain consistency. However writable slaves are
514	 * an exception: if a key is created in the slave and an expire is assigned
515	 * to it, we need a way to expire such a key, since the master does not know
516	 * anything about such a key.
517	 *
518	 * In order to do so, we track keys created in the slave side with an expire
519	 * set, and call the expireSlaveKeys() function from time to time in order to
520	 * reclaim the keys if they already expired.
521	 *
522	 * Note that the use case we are trying to cover here, is a popular one where
523	 * slaves are put in writable mode in order to compute slow operations in
524	 * the slave side that are mostly useful to actually read data in a more
525	 * processed way. Think at sets intersections in a tmp key, with an expire so
526	 * that it is also used as a cache to avoid intersecting every time.
527	 *
528	 * This implementation is currently not perfect but a lot better than leaking
529	 * the keys as implemented in 3.2.
530	 *----------------------------------------------------------------------------*/
531	
532	/* The dictionary where we remember key names and database ID of keys we may
533	 * want to expire from the slave. Since this function is not often used we
534	 * don't even care to initialize the database at startup. We'll do it once
535	 * the feature is used the first time, that is, when rememberSlaveKeyWithExpire()
536	 * is called.
537	 *
538	 * The dictionary has an SDS string representing the key as the hash table
539	 * key, while the value is a 64 bit unsigned integer with the bits corresponding
540	 * to the DB where the keys may exist set to 1. Currently the keys created
541	 * with a DB id > 63 are not expired, but a trivial fix is to set the bitmap
542	 * to the max 64 bit unsigned value when we know there is a key with a DB
543	 * ID greater than 63, and check all the configured DBs in such a case. */
544	dict *slaveKeysWithExpire = NULL;
545	
546	/* Check the set of keys created by the master with an expire set in order to
547	 * check if they should be evicted. */
548	void expireSlaveKeys(void) {
549	    if (slaveKeysWithExpire == NULL ||
550	        dictSize(slaveKeysWithExpire) == 0) return;
551	
552	    int cycles = 0, noexpire = 0;
553	    mstime_t start = mstime();
554	    while(1) {
555	        dictEntry *de = dictGetRandomKey(slaveKeysWithExpire);
556	        sds keyname = dictGetKey(de);
557	        uint64_t dbids = dictGetUnsignedIntegerVal(de);
558	        uint64_t new_dbids = 0;
559	
560	        /* Check the key against every database corresponding to the
561	         * bits set in the value bitmap. */
562	        int dbid = 0;
563	        while(dbids && dbid < server.dbnum) {
564	            if ((dbids & 1) != 0) {
565	                redisDb *db = server.db+dbid;
566	                kvobj *kv = dbFindExpires(db, keyname);
567	                int expired = kv && activeExpireCycleTryExpire(server.db+dbid, kv, start);
568	
569	                /* If the key was not expired in this DB, we need to set the
570	                 * corresponding bit in the new bitmap we set as value.
571	                 * At the end of the loop if the bitmap is zero, it means we
572	                 * no longer need to keep track of this key. */
573	                if (kv && !expired) {
574	                    noexpire++;
575	                    new_dbids |= (uint64_t)1 << dbid;
576	                }
577	            }
578	            dbid++;
579	            dbids >>= 1;
580	        }
581	
582	        /* Set the new bitmap as value of the key, in the dictionary
583	         * of keys with an expire set directly in the writable slave. Otherwise
584	         * if the bitmap is zero, we no longer need to keep track of it. */
585	        if (new_dbids)
586	            dictSetUnsignedIntegerVal(de,new_dbids);
587	        else
588	            dictDelete(slaveKeysWithExpire,keyname);
589	
590	        /* Stop conditions: found 3 keys we can't expire in a row or
591	         * time limit was reached. */
592	        cycles++;
593	        if (noexpire > 3) break;
594	        if ((cycles % 64) == 0 && mstime()-start > 1) break;
595	        if (dictSize(slaveKeysWithExpire) == 0) break;
596	    }
597	}
598	
599	/* Track keys that received an EXPIRE or similar command in the context
600	 * of a writable slave. */
601	void rememberSlaveKeyWithExpire(redisDb *db, sds key) {
602	    if (slaveKeysWithExpire == NULL) {
603	        static dictType dt = {
604	            dictSdsHash,                /* hash function */
605	            NULL,                       /* key dup */
606	            NULL,                       /* val dup */
607	            dictSdsKeyCompare,          /* key compare */
608	            dictSdsDestructor,          /* key destructor */
609	            NULL,                       /* val destructor */
610	            NULL                        /* allow to expand */
611	        };
612	        slaveKeysWithExpire = dictCreate(&dt);
613	    }
614	    if (db->id > 63) return;
615	
616	    dictEntry *de = dictAddOrFind(slaveKeysWithExpire, key);
617	    /* If the entry was just created, set it to a copy of the SDS string
618	     * representing the key: we don't want to need to take those keys
619	     * in sync with the main DB. The keys will be removed by expireSlaveKeys()
620	     * as it scans to find keys to remove. */
621	    if (dictGetKey(de) == key) {
622	        dictSetKey(slaveKeysWithExpire, de, sdsdup(key));
623	        dictSetUnsignedIntegerVal(de,0);
624	    }
625	
626	    uint64_t dbids = dictGetUnsignedIntegerVal(de);
627	    dbids |= (uint64_t)1 << db->id;
628	    dictSetUnsignedIntegerVal(de,dbids);
