652	int checkAlreadyExpired(long long when) {
653	    /* EXPIRE with negative TTL, or EXPIREAT with a timestamp into the past
654	     * should never be executed as a DEL when load the AOF or in the context
655	     * of a slave instance.
656	     *
657	     * Instead we add the already expired key to the database with expire time
658	     * (possibly in the past) and wait for an explicit DEL from the master. */
659	    if (server.current_client && server.current_client->flags & CLIENT_MASTER) return 0;
660	    return (when <= commandTimeSnapshot() && !server.loading && !server.masterhost);
661	}
