663	#define EXPIRE_NX (1<<0)
664	#define EXPIRE_XX (1<<1)
665	#define EXPIRE_GT (1<<2)
666	#define EXPIRE_LT (1<<3)
667	
668	/* Parse additional flags of expire commands
669	 *
670	 * Supported flags:
671	 * - NX: set expiry only when the key has no expiry
672	 * - XX: set expiry only when the key has an existing expiry
673	 * - GT: set expiry only when the new expiry is greater than current one
674	 * - LT: set expiry only when the new expiry is less than current one */
675	int parseExtendedExpireArgumentsOrReply(client *c, int *flags) {
676	    int nx = 0, xx = 0, gt = 0, lt = 0;
677	
678	    int j = 3;
679	    while (j < c->argc) {
680	        char *opt = c->argv[j]->ptr;
681	        if (!strcasecmp(opt,"nx")) {
682	            *flags |= EXPIRE_NX;
683	            nx = 1;
684	        } else if (!strcasecmp(opt,"xx")) {
685	            *flags |= EXPIRE_XX;
686	            xx = 1;
687	        } else if (!strcasecmp(opt,"gt")) {
688	            *flags |= EXPIRE_GT;
689	            gt = 1;
690	        } else if (!strcasecmp(opt,"lt")) {
691	            *flags |= EXPIRE_LT;
692	            lt = 1;
693	        } else {
694	            addReplyErrorFormat(c, "Unsupported option %s", opt);
695	            return C_ERR;
696	        }
697	        j++;
698	    }
699

700	    if ((nx && xx) || (nx && gt) || (nx && lt)) {
701	        addReplyError(c, "NX and XX, GT or LT options at the same time are not compatible");
702	        return C_ERR;
703	    }
704	
705	    if (gt && lt) {
706	        addReplyError(c, "GT and LT options at the same time are not compatible");
707	        return C_ERR;
708	    }
709	
710	    return C_OK;
711	}
