713	/*-----------------------------------------------------------------------------
714	 * Expires Commands
715	 *----------------------------------------------------------------------------*/
716	
717	/* This is the generic command implementation for EXPIRE, PEXPIRE, EXPIREAT
718	 * and PEXPIREAT. Because the command second argument may be relative or absolute
719	 * the "basetime" argument is used to signal what the base time is (either 0
720	 * for *AT variants of the command, or the current time for relative expires).
721	 *
722	 * unit is either UNIT_SECONDS or UNIT_MILLISECONDS, and is only used for
723	 * the argv[2] parameter. The basetime is always specified in milliseconds.
724	 *
725	 * Additional flags are supported and parsed via parseExtendedExpireArguments */
726	void expireGenericCommand(client *c, long long basetime, int unit) {
727	    robj *key = c->argv[1], *param = c->argv[2];
728	    long long when; /* unix time in milliseconds when the key will expire. */
729	    long long current_expire = -1;
730	    int flag = 0;
731	
732	    /* checking optional flags */
733	    if (parseExtendedExpireArgumentsOrReply(c, &flag) != C_OK) {
734	        return;
735	    }
736	
737	    if (getLongLongFromObjectOrReply(c, param, &when, NULL) != C_OK)
738	        return;
739	
740	    /* EXPIRE allows negative numbers, but we can at least detect an
741	     * overflow by either unit conversion or basetime addition. */
742	    if (unit == UNIT_SECONDS) {
743	        if (when > LLONG_MAX / 1000 || when < LLONG_MIN / 1000) {
744	            addReplyErrorExpireTime(c);
745	            return;
746	        }
747	        when *= 1000;
748	    }
749	
750	    if (when > LLONG_MAX - basetime) {
751	        addReplyErrorExpireTime(c);
752	        return;
753	    }
754	    when += basetime;
755	
756	    /* No key, return zero. */
757	    kvobj *kv = lookupKeyWrite(c->db,key); 
758	    if (kv == NULL) {
759	        addReply(c,shared.czero);
760	        return;
761	    }
762	
763	    if (flag) {
764	        current_expire = kvobjGetExpire(kv);
765	
766	        /* NX option is set, check current expiry */
767	        if (flag & EXPIRE_NX) {
768	            if (current_expire != -1) {
769	                addReply(c,shared.czero);
770	                return;
771	            }
772	        }
773	
774	        /* XX option is set, check current expiry */
775	        if (flag & EXPIRE_XX) {
776	            if (current_expire == -1) {
777	                /* reply 0 when the key has no expiry */
778	                addReply(c,shared.czero);
779	                return;
780	            }
781	        }
782	
783	        /* GT option is set, check current expiry */
784	        if (flag & EXPIRE_GT) {
785	            /* When current_expire is -1, we consider it as infinite TTL,
786	             * so expire command with gt always fail the GT. */
787	            if (when <= current_expire || current_expire == -1) {
788	                /* reply 0 when the new expiry is not greater than current */
789	                addReply(c,shared.czero);
790	                return;
791	            }
792	        }
793	
794	        /* LT option is set, check current expiry */
795	        if (flag & EXPIRE_LT) {
796	            /* When current_expire -1, we consider it as infinite TTL,
797	             * but 'when' can still be negative at this point, so if there is
798	             * an expiry on the key and it's not less than current, we fail the LT. */
799	            if (current_expire != -1 && when >= current_expire) {
800	                /* reply 0 when the new expiry is not less than current */
801	                addReply(c,shared.czero);
802	                return;
803	            }
804	        }
805	    }
806	
807	    if (checkAlreadyExpired(when)) {
808	        robj *aux;
809	
810	        int deleted = dbGenericDelete(c->db,key,server.lazyfree_lazy_expire,DB_FLAG_KEY_EXPIRED);
811	        serverAssertWithInfo(c,key,deleted);
812	        server.dirty++;
813	
814	        /* Replicate/AOF this as an explicit DEL or UNLINK. */
815	        aux = server.lazyfree_lazy_expire ? shared.unlink : shared.del;
816	        rewriteClientCommandVector(c,2,aux,key);
817	        keyModified(c,c->db,key,NULL,1);
818	        notifyKeyspaceEvent(NOTIFY_GENERIC,"del",key,c->db->id);
819	        addReply(c, shared.cone);
820	        return;
821	    } else {
822	        kv = setExpire(c,c->db,key,when); /* might realloc kv */
823	        addReply(c,shared.cone);
824	        /* Propagate as PEXPIREAT millisecond-timestamp
825	         * Only rewrite the command arg if not already PEXPIREAT */
826	        if (c->cmd->proc != pexpireatCommand) {
827	            rewriteClientCommandArgument(c,0,shared.pexpireat);
828	        }
829	
830	        /* Avoid creating a string object when it's the same as argv[2] parameter  */
831	        if (basetime != 0 || unit == UNIT_SECONDS) {
832	            robj *when_obj = createStringObjectFromLongLong(when);
833	            rewriteClientCommandArgument(c,2,when_obj);
834	            decrRefCount(when_obj);
835	        }
836	
837	        keyModified(c,c->db,key,kv,1);
838	        notifyKeyspaceEvent(NOTIFY_GENERIC,"expire",key,c->db->id);
839	        KSN_INVALIDATE_KVOBJ(kv);
840	        server.dirty++;
841	        return;
842	    }
843	}
