865	/* Implements TTL, PTTL, EXPIRETIME and PEXPIRETIME */
866	void ttlGenericCommand(client *c, int output_ms, int output_abs) {
867	    long long expire, ttl = -1;
868	
869	    /* If the key does not exist at all, return -2 */
870	    kvobj *kv = lookupKeyReadWithFlags(c->db,c->argv[1],LOOKUP_NOTOUCH);
871	    if (kv == NULL) {
872	        addReplyLongLong(c,-2);
873	        return;
874	    }
875	
876	    /* The key exists. Return -1 if it has no expire, or the actual
877	     * TTL value otherwise. */
878	    expire = kvobjGetExpire(kv);
879	    if (expire != -1) {
880	        ttl = output_abs ? expire : expire-commandTimeSnapshot();
881	        if (ttl < 0) ttl = 0;
882	    }
883	    if (ttl == -1) {
884	        addReplyLongLong(c,-1);
885	    } else {
886	        addReplyLongLong(c,output_ms ? ttl : ((ttl+500)/1000));
887	    }
888	}
