224	/* Run debug assertions based on server.dbg_assert_flags.
225	 *
226	 * DBG_ASSERT_KEYSIZES:   Triggered by DEBUG KEYSIZES-HIST-ASSERT 1
227	 * DBG_ASSERT_ALLOC_SLOT: Triggered by DEBUG ALLOCSIZE-SLOTS-ASSERT 1
228	 */
229	void dbgRunAssertions(redisDb *db) {
230	    /* Don't assert during nested calls. Intermediate state may be inconsistent. */
231	    if (server.execution_nesting) return;
232	
233	    /* Don't assert during RDB loading. Database may be in inconsistent state. */
234	    if (server.loading || server.async_loading) return;
235	
236	    /* Don't assert during ASM background trim or import.
237	     * - During background trim, histogram delta hasn't been applied yet.
238	     * - During import, assertions can introduce slowdown and cause ASM tests to fail. */
239	    if (asmIsBgTrimRunning() || asmImportInProgress()) return;
240	
241	    if (server.dbg_assert_flags & DBG_ASSERT_KEYSIZES)
242	        dbgAssertKeysizesHist(db);
243	
244	    if (server.dbg_assert_flags & DBG_ASSERT_ALLOC_SLOT)
245	        dbgAssertAllocSizePerSlot(db);
246	}
