248	/* Lookup a kvobj for read or write operations, or return NULL if the it is not
249	 * found in the specified DB. This function implements the functionality of
250	 * lookupKeyRead(), lookupKeyWrite() and their ...WithFlags() variants.
251	 *
252	 * link - If key found, return the link of the key.
253	 *        If key not found, return the bucket link, where the key should be added.
254	 *        Or NULL if dict wasn't allocated yet.
255	 *
256	 * Side-effects of calling this function:
257	 *
258	 * 1. A key gets expired if it reached it's TTL.
259	 * 2. The key's last access time is updated.
260	 * 3. The global keys hits/misses stats are updated (reported in INFO).
261	 * 4. If keyspace notifications are enabled, a "keymiss" notification is fired.
262	 *
263	 * Flags change the behavior of this command:
264	 *
265	 *  LOOKUP_NONE (or zero): No special flags are passed.
266	 *  LOOKUP_NOTOUCH: Don't alter the last access time of the key.
267	 *  LOOKUP_NONOTIFY: Don't trigger keyspace event on key miss.
268	 *  LOOKUP_NOSTATS: Don't increment key hits/misses counters.
269	 *  LOOKUP_WRITE: Prepare the key for writing (delete expired keys even on
270	 *                replicas, use separate keyspace stats and events (TODO)).
271	 *  LOOKUP_NOEXPIRE: Perform expiration check, but avoid deleting the key,
272	 *                   so that we don't have to propagate the deletion.
273	 *
274	 * Note: this function also returns NULL if the key is logically expired but
275	 * still existing, in case this is a replica and the LOOKUP_WRITE is not set.
276	 * Even if the key expiry is master-driven, we can correctly report a key is
277	 * expired on replicas even if the master is lagging expiring our key via DELs
278	 * in the replication link. */
279	kvobj *lookupKey(redisDb *db, robj *key, int flags, dictEntryLink *link) {
280	
281	    kvobj *val = dbFindByLink(db, key->ptr, link);
282	
283	    if (val) {
284	        /* Forcing deletion of expired keys on a replica makes the replica
285	         * inconsistent with the master. We forbid it on readonly replicas, but
286	         * we have to allow it on writable replicas to make write commands
287	         * behave consistently.
288	         *
289	         * It's possible that the WRITE flag is set even during a readonly
290	         * command, since the command may trigger events that cause modules to
291	         * perform additional writes. */
292	        int is_ro_replica = server.masterhost && server.repl_slave_ro;
293	        int expire_flags = 0;
294	        if (flags & LOOKUP_WRITE && !is_ro_replica)
295	            expire_flags |= EXPIRE_FORCE_DELETE_EXPIRED;
296	        if (flags & LOOKUP_NOEXPIRE)
297	            expire_flags |= EXPIRE_AVOID_DELETE_EXPIRED;
298	        if (flags & LOOKUP_ACCESS_EXPIRED)
299	            expire_flags |= EXPIRE_ALLOW_ACCESS_EXPIRED;
300	        if (flags & LOOKUP_ACCESS_TRIMMED)
301	            expire_flags |= EXPIRE_ALLOW_ACCESS_TRIMMED;
302	        if (expireIfNeeded(db, key, val, expire_flags) != KEY_VALID) {
303	            /* The key is no longer valid. */
304	            val = NULL;
305	            if (link) *link = NULL;
306	        }
307	    }
308	
309	    if (val) {
310	        /* Update the access time for the ageing algorithm.
311	         * Don't do it if we have a saving child, as this will trigger
312	         * a copy on write madness. */
313	        if (((flags & LOOKUP_NOTOUCH) == 0) &&
314	            (server.current_client && server.current_client->flags & CLIENT_NO_TOUCH) &&
315	            (server.executing_client && server.executing_client->cmd->proc != touchCommand))
316	            flags |= LOOKUP_NOTOUCH;
317	        if (!hasActiveChildProcess() && !(flags & LOOKUP_NOTOUCH)){
318	            if (server.maxmemory_policy & MAXMEMORY_FLAG_LFU) {
319	                updateLFU(val);
320	            } else if (!(server.maxmemory_policy & MAXMEMORY_FLAG_LRM)) {
321	                /* LRM policy should NOT update timestamp on reads. */
322	                val->lru = LRU_CLOCK();
323	            }
324	        }
325	
326	        if (!(flags & (LOOKUP_NOSTATS | LOOKUP_WRITE)))
327	            server.stat_keyspace_hits++;
328	        /* TODO: Use separate hits stats for WRITE */
329	    } else {
330	        if (!(flags & (LOOKUP_NONOTIFY | LOOKUP_WRITE)))
331	            notifyKeyspaceEvent(NOTIFY_KEY_MISS, "keymiss", key, db->id);
332	        if (!(flags & (LOOKUP_NOSTATS | LOOKUP_WRITE)))
333	            server.stat_keyspace_misses++;
334	        /* TODO: Use separate misses stats and notify event for WRITE */
335	    }
336	
337	    return val;
338	}
