1013	/* Remove all data (keys and functions) from all the databases in a
1014	 * Redis server. If callback is given the function is called from
1015	 * time to time to signal that work is in progress.
1016	 *
1017	 * The dbnum can be -1 if all the DBs should be flushed, or the specified
1018	 * DB number if we want to flush only a single Redis database number.
1019	 *
1020	 * Flags are be EMPTYDB_NO_FLAGS if no special flags are specified or
1021	 * EMPTYDB_ASYNC if we want the memory to be freed in a different thread
1022	 * and the function to return ASAP. EMPTYDB_NOFUNCTIONS can also be set
1023	 * to specify that we do not want to delete the functions.
1024	 *
1025	 * On success the function returns the number of keys removed from the
1026	 * database(s). Otherwise -1 is returned in the specific case the
1027	 * DB number is out of range, and errno is set to EINVAL. */
1028	long long emptyData(int dbnum, int flags, void(callback)(dict*)) {
1029	    int async = (flags & EMPTYDB_ASYNC);
1030	    int with_functions = !(flags & EMPTYDB_NOFUNCTIONS);
1031	    RedisModuleFlushInfoV1 fi = {REDISMODULE_FLUSHINFO_VERSION,!async,dbnum};
1032	    long long removed = 0;
1033	
1034	    if (dbnum < -1 || dbnum >= server.dbnum) {
1035	        errno = EINVAL;
1036	        return -1;
1037	    }
1038	
1039	    if (dbnum == -1 || dbnum == 0)
1040	        asmCancelTrimJobs();
1041	
1042	    /* Fire the flushdb modules event. */
1043	    moduleFireServerEvent(REDISMODULE_EVENT_FLUSHDB,
1044	                          REDISMODULE_SUBEVENT_FLUSHDB_START,
1045	                          &fi);
1046	
1047	    /* Make sure the WATCHed keys are affected by the FLUSH* commands.
1048	     * Note that we need to call the function while the keys are still
1049	     * there. */
1050	    signalFlushedDb(dbnum, async, NULL);
1051	
1052	    /* Empty redis database structure. */
1053	    removed = emptyDbStructure(server.db, dbnum, async, callback);
1054	
1055	    if (dbnum == -1) flushSlaveKeysWithExpireList();
1056	
1057	    if (with_functions) {
1058	        serverAssert(dbnum == -1);
1059	        functionsLibCtxClearCurrent(async);
1060	    }
1061	
1062	    /* Also fire the end event. Note that this event will fire almost
1063	     * immediately after the start event if the flush is asynchronous. */
1064	    moduleFireServerEvent(REDISMODULE_EVENT_FLUSHDB,
1065	                          REDISMODULE_SUBEVENT_FLUSHDB_END,
1066	                          &fi);
1067	
1068	    return removed;
1069	}
