1111	/* Move entries whose robj keys belong to the given slot from src dict to dst.
1112	 * Matching entries are removed from src and added to dst. */
1113	void streamMoveIdmpKeys(dict *src, dict *dst, int slot) {
1114	    if (dictSize(src) == 0) return;
1115	
1116	    dictIterator *di = dictGetSafeIterator(src);
1117	    dictEntry *de;
1118	    while ((de = dictNext(di)) != NULL) {
1119	        robj *key = dictGetKey(de);
1120	        if (calculateKeySlot(key->ptr) == slot) {
1121	            if (dictAddRaw(dst, key, NULL)) {
1122	                incrRefCount(key);
1123	            }
1124	            dictDelete(src, key);
1125	        }
1126	    }
1127	    dictReleaseIterator(di);
1128	}
