1173	void signalFlushedDb(int dbid, int async, slotRangeArray *slots) {
1174	    int startdb, enddb;
1175	    if (dbid == -1) {
1176	        startdb = 0;
1177	        enddb = server.dbnum-1;
1178	    } else {
1179	        startdb = enddb = dbid;
1180	    }
1181	
1182	    for (int j = startdb; j <= enddb; j++) {
1183	        scanDatabaseForDeletedKeys(&server.db[j], NULL, slots);
1184	        touchAllWatchedKeysInDb(&server.db[j], NULL, slots);
1185	    }
1186	
1187	    trackingInvalidateKeysOnFlush(async);
1188	
1189	    /* Changes in this method may take place in swapMainDbWithTempDb as well,
1190	     * where we execute similar calls, but with subtle differences as it's
1191	     * not simply flushing db. */
1192	}
