1328	/* Common flush command implementation for FLUSHALL, FLUSHDB and SFLUSH.
1329	 *
1330	 * Return 1 indicates that flush SYNC is actually running in bg as blocking ASYNC
1331	 * Return 0 otherwise
1332	 *
1333	 * trim_ctx - provided only by SFLUSH command, otherwise NULL. Contains slots to
1334	 *            be used on completion to reply with the slots flush result. 
1335	 */
1336	int flushCommandCommon(client *c, int type, int flags, asmTrimCtx *trim_ctx) {
1337	    int blocking_async = 0; /* Flush SYNC option to run as blocking ASYNC */
1338	
1339	    /* in case of SYNC, check if we can optimize and run it in bg as blocking ASYNC */
1340	    if ((!(flags & EMPTYDB_ASYNC)) && (!(c->flags & CLIENT_AVOID_BLOCKING_ASYNC_FLUSH))) {
1341	        /* Run as ASYNC */
1342	        flags |= EMPTYDB_ASYNC;
1343	        blocking_async = 1;
1344	    }
1345	
1346	    /* Cancel all ASM tasks that overlap with the given slot ranges. */
1347	    clusterAsmCancelBySlotRangeArray(trim_ctx ? trim_ctx->slots : NULL, c->argv[0]->ptr);
1348	
1349	    if (type == FLUSH_TYPE_ALL)
1350	        flushAllDataAndResetRDB(flags | EMPTYDB_NOFUNCTIONS);
1351	    else
1352	        server.dirty += emptyData(c->db->id,flags | EMPTYDB_NOFUNCTIONS,NULL);
1353	
1354	    /* Without the forceCommandPropagation, when DB(s) was already empty,
1355	     * FLUSHALL\FLUSHDB will not be replicated nor put into the AOF. */
1356	    forceCommandPropagation(c, PROPAGATE_REPL | PROPAGATE_AOF);
1357	
1358	    /* if blocking ASYNC, block client and add completion job request to BIO lazyfree
1359	     * worker's queue. To be called and reply with OK only after all preceding pending
1360	     * lazyfree jobs in queue were processed */
1361	    if (blocking_async) {
1362	        blockClientForAsyncFlush(c);
1363	        /* Retain trim_ctx if provided so kvsAsyncFreeDoneCB can release it later */
1364	        if (trim_ctx) {
1365	            asmBgTrimCounterIncr();
1366	            asmTrimCtxRetain(trim_ctx);
1367	        }
1368	        bioCreateCompRq(BIO_WORKER_LAZY_FREE, kvsAsyncFreeDoneCB, c->id, trim_ctx);
1369	    }
1370	
1371	#if defined(USE_JEMALLOC)
1372	    /* jemalloc 5 doesn't release pages back to the OS when there's no traffic.
1373	     * for large databases, flushdb blocks for long anyway, so a bit more won't
1374	     * harm and this way the flush and purge will be synchronous.
1375	     *
1376	     * Take care purge only FLUSHDB for sync flow. FLUSHALL sync flow already
1377	     * applied at flushAllDataAndResetRDB. Async flow will apply only later on */
1378	    if ((type != FLUSH_TYPE_ALL) && (!(flags & EMPTYDB_ASYNC))) {
1379	        /* Only clear the current thread cache.
1380	         * Ignore the return call since this will fail if the tcache is disabled. */
1381	        je_mallctl("thread.tcache.flush", NULL, NULL, NULL, 0);
1382	
1383	        jemalloc_purge();
1384	    }
1385	#endif
1386	    return blocking_async;
1387	}
