2270	void moveCommand(client *c) {
2271	    redisDb *src, *dst;
2272	    int srcid, dbid;
2273	    uint64_t hashExpireTime = EB_EXPIRE_TIME_INVALID;
2274	
2275	    if (server.cluster_enabled) {
2276	        addReplyError(c,"MOVE is not allowed in cluster mode");
2277	        return;
2278	    }
2279	
2280	    /* Obtain source and target DB pointers */
2281	    src = c->db;
2282	    srcid = c->db->id;
2283	
2284	    if (getIntFromObjectOrReply(c, c->argv[2], &dbid, NULL) != C_OK)
2285	        return;
2286	
2287	    if (selectDb(c,dbid) == C_ERR) {
2288	        addReplyError(c,"DB index is out of range");
2289	        return;
2290	    }
2291	    dst = c->db;
2292	    selectDb(c,srcid); /* Back to the source DB */
2293	
2294	    /* If the user is moving using as target the same
2295	     * DB as the source DB it is probably an error. */
2296	    if (src == dst) {
2297	        addReplyErrorObject(c,shared.sameobjecterr);
2298	        return;
2299	    }
2300	
2301	    /* Record incompatible operations in cluster mode */
2302	    server.stat_cluster_incompatible_ops++;
2303	
2304	    /* Check if the element exists and get a reference */
2305	    kvobj *kv = lookupKeyWrite(c->db,c->argv[1]);
2306	    if (!kv) {
2307	        addReply(c,shared.czero);
2308	        return;
2309	    }
2310	
2311	    /* Return zero if the key already exists in the target DB */
2312	    dictEntryLink dstBucket;
2313	    if (lookupKey(dst, c->argv[1], LOOKUP_WRITE, &dstBucket) != NULL)  {
2314	        addReply(c,shared.czero);
2315	        return;
2316	    }
2317	
2318	    int slot = getKeySlot(c->argv[1]->ptr);
2319	
2320	    /* If hash with expiration on fields, remove it from DB subexpires and keep
2321	     * aside registered expiration time. Must be before removal of the
2322	     * object since it embeds ExpireMeta that is used by subexpires */
2323	    if (kv->type == OBJ_HASH)
2324	        hashExpireTime = estoreRemove(src->subexpires, slot, kv);
2325	
2326	    /* Move a side metadata before dbDelete() */
2327	    KeyMetaSpec keymeta;
2328	    keyMetaSpecInit(&keymeta);
2329	    keyMetaOnMove(kv, c->argv[1], srcid, dbid, &keymeta);
2330	
2331	    incrRefCount(kv);            /* ref counter = 1->2 */
2332	    dbDelete(src,c->argv[1]);    /* ref counter = 2->1 */
2333	
2334	    dbAddInternal(dst, c->argv[1], &kv, &dstBucket, &keymeta);
2335	
2336	    /* If object of type hash with expiration on fields. Taken care to add the
2337	     * hash to subexpires of `dst` only after dbDelete(). */
2338	    if (hashExpireTime != EB_EXPIRE_TIME_INVALID)
2339	        estoreAdd(dst->subexpires, slot, kv, hashExpireTime);
2340	
2341	    /* Register stream IDMP tracking in the destination DB. */
2342	    if (kv->type == OBJ_STREAM)
2343	        streamKeyLoaded(dst, c->argv[1], kv);
2344	
2345	    keyModified(c,src,c->argv[1],NULL,1);
2346	    keyModified(c,dst,c->argv[1],kv,1);
2347	    notifyKeyspaceEvent(NOTIFY_GENERIC, "move_from", c->argv[1],src->id);
2348	    notifyKeyspaceEvent(NOTIFY_GENERIC, "move_to", c->argv[1],dst->id);
2349	    KSN_INVALIDATE_KVOBJ(kv);
2350	
2351	    server.dirty++;
2352	    addReply(c,shared.cone);
2353	}
