2355	void copyCommand(client *c) {
2356	    kvobj *o;
2357	    redisDb *src, *dst;
2358	    int srcid, dbid;
2359	    int j, replace = 0, delete = 0;
2360	
2361	    /* Obtain source and target DB pointers 
2362	     * Default target DB is the same as the source DB 
2363	     * Parse the REPLACE option and targetDB option. */
2364	    src = c->db;
2365	    dst = c->db;
2366	    srcid = c->db->id;
2367	    dbid = c->db->id;
2368	    for (j = 3; j < c->argc; j++) {
2369	        int additional = c->argc - j - 1;
2370	        if (!strcasecmp(c->argv[j]->ptr,"replace")) {
2371	            replace = 1;
2372	        } else if (!strcasecmp(c->argv[j]->ptr, "db") && additional >= 1) {
2373	            if (getIntFromObjectOrReply(c, c->argv[j+1], &dbid, NULL) != C_OK)
2374	                return;
2375	
2376	            if (selectDb(c, dbid) == C_ERR) {
2377	                addReplyError(c,"DB index is out of range");
2378	                return;
2379	            }
2380	            dst = c->db;
2381	            selectDb(c,srcid); /* Back to the source DB */
2382	            j++; /* Consume additional arg. */
2383	        } else {
2384	            addReplyErrorObject(c,shared.syntaxerr);
2385	            return;
2386	        }
2387	    }
2388	
2389	    if ((server.cluster_enabled == 1) && (srcid != 0 || dbid != 0)) {
2390	        addReplyError(c,"Copying to another database is not allowed in cluster mode");
2391	        return;
2392	    }
2393	
2394	    /* If the user select the same DB as
2395	     * the source DB and using newkey as the same key
2396	     * it is probably an error. */
2397	    robj *key = c->argv[1];
2398	    robj *newkey = c->argv[2];
2399	    if (src == dst && (sdscmp(key->ptr, newkey->ptr) == 0)) {
2400	        addReplyErrorObject(c,shared.sameobjecterr);
2401	        return;
2402	    }
2403	
2404	    if (srcid != 0 || dbid != 0) {
2405	        server.stat_cluster_incompatible_ops++;
2406	    }
2407	
2408	    /* Check if the element exists and get a reference */
2409	    o = lookupKeyRead(c->db, key);
2410	    if (!o) {
2411	        addReply(c,shared.czero);
2412	        return;
2413	    }
2414	
2415	    /* Return zero if the key already exists in the target DB. 
2416	     * If REPLACE option is selected, delete newkey from targetDB. */
2417	    kvobj *destval = lookupKeyWrite(dst,newkey);
2418	    if (destval != NULL) {
2419	        if (replace) {
2420	            delete = 1;
2421	        } else {
2422	            addReply(c,shared.czero);
2423	            return;
2424	        }
2425	    }
2426	    int destoldtype = destval ? destval->type : -1;
2427	    int destnewtype = o->type;
2428	
2429	    /* Duplicate object according to object's type. */
2430	    robj *newobj;
2431	    uint64_t minHashExpire = EB_EXPIRE_TIME_INVALID; /* HFE feature */
2432	    switch(o->type) {
2433	        case OBJ_STRING: newobj = dupStringObject(o); break;
2434	        case OBJ_LIST: newobj = listTypeDup(o); break;
2435	        case OBJ_SET: newobj = setTypeDup(o); break;
2436	        case OBJ_ZSET: newobj = zsetDup(o); break;
2437	        case OBJ_HASH: newobj = hashTypeDup(o, &minHashExpire); break;
2438	        case OBJ_STREAM: newobj = streamDup(o); break;
2439	#ifdef ENABLE_GCRA
2440	        case OBJ_GCRA: newobj = gcraDup(o); break;
2441	#endif
2442	        case OBJ_MODULE:
2443	            newobj = moduleTypeDupOrReply(c, key, newkey, dst->id, o);
2444	            if (!newobj) return;
2445	            break;
2446	        case OBJ_ARRAY: newobj = arrayTypeDup(o); break;
2447	        default:
2448	            addReplyError(c, "unknown type object");
2449	            return;
2450	    }
2451	
2452	    if (delete) {
2453	        dbDelete(dst,newkey);
2454	    }
2455	
2456	    /* Prepare metadata for the new key */
2457	    KeyMetaSpec keymeta;
2458	    keyMetaSpecInit(&keymeta);
2459	    if (o->metabits) keyMetaOnCopy(o, key, newkey, c->db->id, dst->id, &keymeta);
2460	
2461	    kvobj *kvCopy = dbAddInternal(dst, newkey, &newobj, NULL, &keymeta);
2462	
2463	    /* If minExpiredField was set, then the object is hash with expiration
2464	     * on fields and need to register it in global HFE DS */
2465	    if (minHashExpire != EB_EXPIRE_TIME_INVALID)
2466	        estoreAdd(dst->subexpires, getKeySlot(newkey->ptr), kvCopy, minHashExpire);
2467	
2468	    /* Register copied stream with IDMP producers for cron-based expiration. */
2469	    if (kvCopy->type == OBJ_STREAM)
2470	        streamKeyLoaded(dst, newkey, kvCopy);
2471	
2472	    /* OK! key copied. Signal modification */
2473	    keyModified(c,dst,c->argv[2],kvCopy,1);
2474	    notifyKeyspaceEvent(NOTIFY_GENERIC,"copy_to",c->argv[2],dst->id);
2475	    KSN_INVALIDATE_KVOBJ(kvCopy);
2476	
2477	    /* `delete` implies the destination key was overwritten */
2478	    if (delete) {
2479	        notifyKeyspaceEvent(NOTIFY_OVERWRITTEN, "overwritten", c->argv[2], dst->id);
2480	        if (destoldtype != destnewtype)
2481	            notifyKeyspaceEvent(NOTIFY_TYPE_CHANGED, "type_changed", c->argv[2], dst->id);
2482	    }
2483	
2484	    server.dirty++;
2485	    addReply(c,shared.cone);
2486	}
