2488	/* Helper function for dbSwapDatabases(): scans the list of keys that have
2489	 * one or more blocked clients for B[LR]POP or other blocking commands
2490	 * and signal the keys as ready if they are of the right type. See the comment
2491	 * where the function is used for more info. */
2492	void scanDatabaseForReadyKeys(redisDb *db) {
2493	    dictEntry *de;
2494	    dictIterator di;
2495	    dictInitSafeIterator(&di, db->blocking_keys);
2496	    while((de = dictNext(&di)) != NULL) {
2497	        robj *key = dictGetKey(de);
2498	        kvobj *kv = dbFind(db, key->ptr);
2499	        if (kv)
2500	            signalKeyAsReady(db, key, kv->type);
2501	    }
2502	    dictResetIterator(&di);
2503	}
