2505	/* Since we are unblocking XREADGROUP clients in the event the key was
2506	 * deleted/overwritten we must do the same in case the database was
2507	 * flushed/swapped. If 'slots' is not NULL, only keys in the specified slot
2508	 * range are considered. */
2509	void scanDatabaseForDeletedKeys(redisDb *emptied, redisDb *replaced_with, slotRangeArray *slots) {
2510	    dictEntry *de;
2511	    dictIterator di;
2512	
2513	    dictInitSafeIterator(&di, emptied->blocking_keys);
2514	    while((de = dictNext(&di)) != NULL) {
2515	        robj *key = dictGetKey(de);
2516	        /* Check if key belongs to the slot range. */
2517	        if (slots && !slotRangeArrayContains(slots, keyHashSlot(key->ptr, sdslen(key->ptr))))
2518	            continue;
2519	        int existed = 0, exists = 0;
2520	        int original_type = -1, curr_type = -1;
2521	
2522	        kvobj *kv = dbFind(emptied, key->ptr);
2523	        if (kv) {
2524	            original_type = kv->type;
2525	            existed = 1;
2526	        }
2527	
2528	        if (replaced_with) {
2529	            kv = dbFind(replaced_with, key->ptr);
2530	            if (kv) {
2531	                curr_type = kv->type;
2532	                exists = 1;
2533	            }
2534	        }
2535	        /* We want to try to unblock any client using a blocking XREADGROUP */
2536	        if ((existed && !exists) || original_type != curr_type)
2537	            signalDeletedKeyAsReady(emptied, key, original_type);
2538	    }
2539	    dictResetIterator(&di);
2540	}
