2542	/* Swap two databases at runtime so that all clients will magically see
2543	 * the new database even if already connected. Note that the client
2544	 * structure c->db points to a given DB, so we need to be smarter and
2545	 * swap the underlying referenced structures, otherwise we would need
2546	 * to fix all the references to the Redis DB structure.
2547	 *
2548	 * Returns C_ERR if at least one of the DB ids are out of range, otherwise
2549	 * C_OK is returned. */
2550	int dbSwapDatabases(int id1, int id2) {
2551	    if (id1 < 0 || id1 >= server.dbnum ||
2552	        id2 < 0 || id2 >= server.dbnum) return C_ERR;
2553	    if (id1 == id2) return C_OK;
2554	    redisDb aux = server.db[id1];
2555	    redisDb *db1 = &server.db[id1], *db2 = &server.db[id2];
2556	
2557	    /* Swapdb should make transaction fail if there is any
2558	     * client watching keys */
2559	    touchAllWatchedKeysInDb(db1, db2, NULL);
2560	    touchAllWatchedKeysInDb(db2, db1, NULL);
2561	
2562	    /* Try to unblock any XREADGROUP clients if the key no longer exists. */
2563	    scanDatabaseForDeletedKeys(db1, db2, NULL);
2564	    scanDatabaseForDeletedKeys(db2, db1, NULL);
2565	
2566	    /* Swap hash tables. Note that we don't swap blocking_keys,
2567	     * ready_keys and watched_keys, since we want clients to
2568	     * remain in the same DB they were. */
2569	    db1->keys = db2->keys;
2570	    db1->expires = db2->expires;
2571	    db1->subexpires = db2->subexpires;
2572	    db1->stream_idmp_keys = db2->stream_idmp_keys;
2573	    db1->avg_ttl = db2->avg_ttl;
2574	    db1->expires_cursor = db2->expires_cursor;
2575	
2576	    db2->keys = aux.keys;
2577	    db2->expires = aux.expires;
2578	    db2->subexpires = aux.subexpires;
2579	    db2->stream_idmp_keys = aux.stream_idmp_keys;
2580	    db2->avg_ttl = aux.avg_ttl;
2581	    db2->expires_cursor = aux.expires_cursor;
2582	
2583	    /* Now we need to handle clients blocked on lists: as an effect
2584	     * of swapping the two DBs, a client that was waiting for list
2585	     * X in a given DB, may now actually be unblocked if X happens
2586	     * to exist in the new version of the DB, after the swap.
2587	     *
2588	     * However normally we only do this check for efficiency reasons
2589	     * in dbAdd() when a list is created. So here we need to rescan
2590	     * the list of clients blocked on lists and signal lists as ready
2591	     * if needed. */
2592	    scanDatabaseForReadyKeys(db1);
2593	    scanDatabaseForReadyKeys(db2);
2594	    return C_OK;
2595	}
