2700	/* Set an expire to the specified key. If the expire is set in the context
2701	 * of an user calling a command 'c' is the client, otherwise 'c' is set
2702	 * to NULL. The 'when' parameter is the absolute unix time in milliseconds
2703	 * after which the key will no longer be considered valid.
2704	 * 
2705	 * Note: It may reallocate kvobj. The returned ref may point to a new object. */
2706	kvobj *setExpire(client *c, redisDb *db, robj *key, long long when) {
2707	    return setExpireByLink(c,db,key->ptr,when,NULL);
2708	}
