2757	/* Retrieve the expiration time for the specified key.
2758	 * Returns -1 if the key has no expiration set or doesn't exists
2759	 *
2760	 * To avoid lookup, pass key-value object (`kv`) instead of `key`.
2761	 */
2762	long long getExpire(redisDb *db, sds key, kvobj *kv) {
2763	    if (kv == NULL) kv = dbFindExpires(db, key);
2764	    if (kv == NULL) return -1;
2765	    return kvobjGetExpire(kv);
2766	}
