2768	/* Delete the specified expired or evicted key and propagate to replicas.
2769	 * Currently notify_type can only be NOTIFY_EXPIRED or NOTIFY_EVICTED,
2770	 * and it affects other aspects like the latency monitor event name and,
2771	 * which config to look for lazy free, stats var to increment, and so on.
2772	 *
2773	 * key_mem_freed is an out parameter which contains the estimated
2774	 * amount of memory freed due to the trimming (may be NULL) */
2775	static void deleteKeyAndPropagate(redisDb *db, robj *keyobj, int notify_type, long long *key_mem_freed) {
2776	    mstime_t latency;
2777	    int del_flag = notify_type == NOTIFY_EXPIRED ? DB_FLAG_KEY_EXPIRED : DB_FLAG_KEY_EVICTED;
2778	    int lazy_flag = notify_type == NOTIFY_EXPIRED ? server.lazyfree_lazy_expire : server.lazyfree_lazy_eviction;
2779	    char *latency_name = notify_type == NOTIFY_EXPIRED ? "expire-del" : "evict-del";
2780	    char *notify_name = notify_type == NOTIFY_EXPIRED ? "expired" : "evicted";
2781	
2782	    /* The key needs to be converted from static to heap before deleted */
2783	    int static_key = keyobj->refcount == OBJ_STATIC_REFCOUNT;
2784	    if (static_key) {
2785	        keyobj = createStringObject(keyobj->ptr, sdslen(keyobj->ptr));
2786	    }
2787	
2788	    serverLog(LL_DEBUG,"key %s %s: deleting it", redactLogCstr((char*)keyobj->ptr), notify_type == NOTIFY_EXPIRED ? "expired" : "evicted");
2789	
2790	    /* We compute the amount of memory freed by db*Delete() alone.
2791	     * It is possible that actually the memory needed to propagate
2792	     * the DEL in AOF and replication link is greater than the one
2793	     * we are freeing removing the key, but we can't account for
2794	     * that otherwise we would never exit the loop.
2795	     *
2796	     * Same for CSC invalidation messages generated by keyModified.
2797	     *
2798	     * AOF and Output buffer memory will be freed eventually so
2799	     * we only care about memory used by the key space.
2800	     *
2801	     * The code here used to first propagate and then record delta
2802	     * using only zmalloc_used_memory but in CRDT we can't do that
2803	     * so we use freeMemoryGetNotCountedMemory to avoid counting
2804	     * AOF and slave buffers */
2805	    if (key_mem_freed) *key_mem_freed = (long long) zmalloc_used_memory() - freeMemoryGetNotCountedMemory();
2806	    latencyStartMonitor(latency);
2807	    dbGenericDelete(db, keyobj, lazy_flag, del_flag);
2808	    latencyEndMonitor(latency);
2809	    latencyAddSampleIfNeeded(latency_name, latency);
2810	    if (key_mem_freed) *key_mem_freed -= (long long) zmalloc_used_memory() - freeMemoryGetNotCountedMemory();
2811	
2812	    notifyKeyspaceEvent(notify_type, notify_name,keyobj, db->id);
2813	    keyModified(NULL, db, keyobj, NULL, 1);
2814	    propagateDeletion(db, keyobj, lazy_flag);
2815	
2816	    if (notify_type == NOTIFY_EXPIRED)
2817	        server.stat_expiredkeys++;
2818	    else
2819	        server.stat_evictedkeys++;
2820	
2821	    if (static_key)
2822	        decrRefCount(keyobj);
2823	}
