2825	/* Delete the specified expired key and propagate. */
2826	void deleteExpiredKeyAndPropagate(redisDb *db, robj *keyobj) {
2827	    deleteKeyAndPropagate(db, keyobj, NOTIFY_EXPIRED, NULL);
2828	}
