2899	/* This function is called when we are going to perform some operation
2900	 * in a given key, but such key may be already logically expired even if
2901	 * it still exists in the database. The main way this function is called
2902	 * is via lookupKey*() family of functions.
2903	 *
2904	 * The behavior of the function depends on the replication role of the
2905	 * instance, because by default replicas do not delete expired keys. They
2906	 * wait for DELs from the master for consistency matters. However even
2907	 * replicas will try to have a coherent return value for the function,
2908	 * so that read commands executed in the replica side will be able to
2909	 * behave like if the key is expired even if still present (because the
2910	 * master has yet to propagate the DEL).
2911	 *
2912	 * In masters as a side effect of finding a key which is expired, such
2913	 * key will be evicted from the database. Also this may trigger the
2914	 * propagation of a DEL/UNLINK command in AOF / replication stream.
2915	 *
2916	 * On replicas, this function does not delete expired keys by default, but
2917	 * it still returns KEY_EXPIRED if the key is logically expired. To force deletion
2918	 * of logically expired keys even on replicas, use the EXPIRE_FORCE_DELETE_EXPIRED
2919	 * flag. Note though that if the current client is executing
2920	 * replicated commands from the master, keys are never considered expired.
2921	 *
2922	 * On the other hand, if you just want expiration check, but need to avoid
2923	 * the actual key deletion and propagation of the deletion, use the
2924	 * EXPIRE_AVOID_DELETE_EXPIRED flag. If also needed to read expired key (that
2925	 * hasn't being deleted yet) then use EXPIRE_ALLOW_ACCESS_EXPIRED.
2926	 *
2927	 * The return value of the function is KEY_VALID if the key is still valid.
2928	 * The function returns KEY_EXPIRED if the key is expired BUT not deleted,
2929	 * or returns KEY_DELETED if the key is expired and deleted. If the key is in a
2930	 * trim job due to slot migration, the function returns KEY_TRIMMED, unless
2931	 * EXPIRE_ALLOW_ACCESS_TRIMMED is set, in which case it returns KEY_VALID.
2932	 *
2933	 * You can optionally pass `kv` to save a lookup.
2934	 */
2935	keyStatus expireIfNeeded(redisDb *db, robj *key, kvobj *kv, int flags) {
2936	    debugAssert(key != NULL || kv != NULL);
2937	
2938	    /* NOTE: Keys in slots scheduled for trimming can still exist for a while.
2939	     * We don't delete it here, return KEY_VALID if allowing access to trimmed
2940	     * keys, and return KEY_TRIMMED otherwise. */
2941	    sds key_name = key ? key->ptr : kvobjGetKey(kv);
2942	    if (asmIsKeyInTrimJob(key_name)) {
2943	        if (server.allow_access_trimmed || (flags & EXPIRE_ALLOW_ACCESS_TRIMMED))
2944	            return KEY_VALID;
2945	
2946	        /* If the slot is not served by this node, we should not allow access
2947	         * to the key, we consider it as trimmed. */
2948	        if (!clusterCanAccessKeysInSlot(getKeySlot(key_name)))
2949	            return KEY_TRIMMED;
2950	    }
2951	
2952	    if ((flags & EXPIRE_ALLOW_ACCESS_EXPIRED) ||
2953	        (!keyIsExpired(db,  key ? key->ptr : NULL, kv)))
2954	        return KEY_VALID;
2955	
2956	    /* If we are running in the context of a replica, instead of
2957	     * evicting the expired key from the database, we return ASAP:
2958	     * the replica key expiration is controlled by the master that will
2959	     * send us synthesized DEL operations for expired keys. The
2960	     * exception is when write operations are performed on writable
2961	     * replicas.
2962	     *
2963	     * In cluster mode, we also return ASAP if we are importing data
2964	     * from the source, to avoid deleting keys that are still in use.
2965	     * We create a fake master client for data import, which can be
2966	     * identified using the CLIENT_MASTER flag.
2967	     *
2968	     * Still we try to return the right information to the caller,
2969	     * that is, KEY_VALID if we think the key should still be valid,
2970	     * KEY_EXPIRED if we think the key is expired but don't want to delete it at this time.
2971	     *
2972	     * When replicating commands from the master, keys are never considered
2973	     * expired. */
2974	    if (server.masterhost != NULL || server.cluster_enabled) {
2975	        if (server.current_client && (server.current_client->flags & CLIENT_MASTER)) return KEY_VALID;
2976	        if (server.masterhost != NULL && !(flags & EXPIRE_FORCE_DELETE_EXPIRED)) return KEY_EXPIRED;
2977	    }
2978	
2979	    /* Check if user configuration disables lazy-expire deletions in current state.
2980	     * This will only apply if the server doesn't mandate key deletion to operate correctly (write commands). */
2981	    if (!(flags & EXPIRE_FORCE_DELETE_EXPIRED) && !confAllowsExpireDel())
2982	        return KEY_EXPIRED;
2983	
2984	    /* In some cases we're explicitly instructed to return an indication of a
2985	     * missing key without actually deleting it, even on masters. */
2986	    if (flags & EXPIRE_AVOID_DELETE_EXPIRED)
2987	        return KEY_EXPIRED;
2988	
2989	    /* If 'expire' action is paused, for whatever reason, then don't expire any key.
2990	     * Typically, at the end of the pause we will properly expire the key OR we
2991	     * will have failed over and the new primary will send us the expire. */
2992	    if (isPausedActionsWithUpdate(PAUSE_ACTION_EXPIRE)) return KEY_EXPIRED;
2993	
2994	    /* Perform deletion */
2995	    if (key) {
2996	        deleteExpiredKeyAndPropagate(db, key);
2997	    } else {
2998	        sds keyname = kvobjGetKey(kv);
2999	        robj *tmpkey = createStringObject(keyname, sdslen(keyname));

3000	        deleteExpiredKeyAndPropagate(db, tmpkey);
3001	        decrRefCount(tmpkey);
3002	    }
3003	    return KEY_DELETED;
3004	}
