3013	/*
3014	 * This functions increases size of the main/expires db to match desired number.
3015	 * In cluster mode resizes all individual dictionaries for slots that this node owns.
3016	 *
3017	 * Based on the parameter `try_expand`, appropriate dict expand API is invoked.
3018	 * if try_expand is set to 1, `dictTryExpand` is used else `dictExpand`.
3019	 * The return code is either `DICT_OK`/`DICT_ERR` for both the API(s).
3020	 * `DICT_OK` response is for successful expansion. However ,`DICT_ERR` response signifies failure in allocation in
3021	 * `dictTryExpand` call and in case of `dictExpand` call it signifies no expansion was performed.
3022	 */
3023	static int dbExpandGeneric(kvstore *kvs, uint64_t db_size, int try_expand) {
3024	    int ret;
3025	    if (server.cluster_enabled) {
3026	        /* We don't know exact number of keys that would fall into each slot, but we can
3027	         * approximate it, assuming even distribution, divide it by the number of slots. */
3028	        int slots = getMyShardSlotCount();
3029	        if (slots == 0) return C_OK;
3030	        db_size = db_size / slots;
3031	        ret = kvstoreExpand(kvs, db_size, try_expand, dbExpandSkipSlot);
3032	    } else {
3033	        ret = kvstoreExpand(kvs, db_size, try_expand, NULL);
3034	    }
3035	
3036	    return ret? C_OK : C_ERR;
3037	}
