3056	/* Find a KV in the main db. Return also link to it.
3057	 *
3058	 * plink - If found, set to the link of the key in the dict.
3059	 *         If not found, set to the bucket where the key should be added.
3060	 *         If set to NULL, then HT of dict not allocated yet.
3061	 */
3062	kvobj *dbFindByLink(redisDb *db, sds key, dictEntryLink *plink) {
3063	    int slot = getKeySlot(key);
3064	    dictEntryLink link, bucket;
3065	
