3115	/* Prepare the getKeysResult struct to hold numkeys, either by using the
3116	 * pre-allocated keysbuf or by allocating a new array on the heap.
3117	 *
3118	 * This function must be called at least once before starting to populate
3119	 * the result, and can be called repeatedly to enlarge the result array.
3120	 */
3121	keyReference *getKeysPrepareResult(getKeysResult *result, int numkeys) {
3122	    /* GETKEYS_RESULT_INIT initializes keys to NULL, point it to the pre-allocated stack
3123	     * buffer here. */
3124	    if (!result->keys) {
3125	        serverAssert(!result->numkeys);
3126	        result->keys = result->keysbuf;
3127	    }
3128	
3129	    /* Resize if necessary */
3130	    if (numkeys > result->size) {
3131	        if (result->keys != result->keysbuf) {
3132	            /* We're not using a static buffer, just (re)alloc */
3133	            result->keys = zrealloc(result->keys, numkeys * sizeof(keyReference));
3134	        } else {
3135	            /* We are using a static buffer, copy its contents */
3136	            result->keys = zmalloc(numkeys * sizeof(keyReference));
3137	            if (result->numkeys)
3138	                memcpy(result->keys, result->keysbuf, result->numkeys * sizeof(keyReference));
3139	        }
3140	        result->size = numkeys;
3141	    }
3142	
3143	    return result->keys;
3144	}
