3157	/* Fetch the keys based of the provided key specs. Returns the number of keys found, or -1 on error.
3158	 * There are several flags that can be used to modify how this function finds keys in a command.
3159	 * 
3160	 * GET_KEYSPEC_INCLUDE_NOT_KEYS: Return 'fake' keys as if they were keys.
3161	 * GET_KEYSPEC_RETURN_PARTIAL:   Skips invalid and incomplete keyspecs but returns the keys
3162	 *                               found in other valid keyspecs. 
3163	 */
3164	int getKeysUsingKeySpecs(struct redisCommand *cmd, robj **argv, int argc, int search_flags, getKeysResult *result) {
3165	    long j, i, last, first, step;
3166	    keyReference *keys;
3167	    serverAssert(result->numkeys == 0); /* caller should initialize or reset it */
3168	
3169	    for (j = 0; j < cmd->key_specs_num; j++) {
3170	        keySpec *spec = cmd->key_specs + j;
3171	        serverAssert(spec->begin_search_type != KSPEC_BS_INVALID);
3172	        /* Skip specs that represent 'fake' keys */
3173	        if ((spec->flags & CMD_KEY_NOT_KEY) && !(search_flags & GET_KEYSPEC_INCLUDE_NOT_KEYS)) {
3174	            continue;
3175	        }
3176	
3177	        first = 0;
3178	        if (spec->begin_search_type == KSPEC_BS_INDEX) {
3179	            first = spec->bs.index.pos;
3180	        } else if (spec->begin_search_type == KSPEC_BS_KEYWORD) {
3181	            int start_index = spec->bs.keyword.startfrom > 0 ? spec->bs.keyword.startfrom : argc+spec->bs.keyword.startfrom;
3182	            int end_index = spec->bs.keyword.startfrom > 0 ? argc-1: 1;
3183	            for (i = start_index; i != end_index; i = start_index <= end_index ? i + 1 : i - 1) {
3184	                if (i >= argc || i < 1)
3185	                    break;
3186	                if (!strcasecmp((char*)argv[i]->ptr,spec->bs.keyword.keyword)) {
3187	                    first = i+1;
3188	                    break;
3189	                }
3190	            }
3191	            /* keyword not found */
3192	            if (!first) {
3193	                continue;
3194	            }
3195	        } else {
3196	            /* unknown spec */
3197	            goto invalid_spec;
3198	        }
