2600	void swapMainDbWithTempDb(redisDb *tempDb) {
2601	    for (int i=0; i<server.dbnum; i++) {
2602	        redisDb aux = server.db[i];
2603	        redisDb *activedb = &server.db[i], *newdb = &tempDb[i];
2604	
2605	        /* Swapping databases should make transaction fail if there is any
2606	         * client watching keys. */
2607	        touchAllWatchedKeysInDb(activedb, newdb, NULL);
2608	
2609	        /* Try to unblock any XREADGROUP clients if the key no longer exists. */
2610	        scanDatabaseForDeletedKeys(activedb, newdb, NULL);
2611	
2612	        /* Swap hash tables. Note that we don't swap blocking_keys,
2613	         * ready_keys and watched_keys, since clients 
2614	         * remain in the same DB they were. */
2615	        activedb->keys = newdb->keys;
2616	        activedb->expires = newdb->expires;
2617	        activedb->subexpires = newdb->subexpires;
2618	        activedb->stream_idmp_keys = newdb->stream_idmp_keys;
2619	        activedb->avg_ttl = newdb->avg_ttl;
2620	        activedb->expires_cursor = newdb->expires_cursor;
2621	
2622	        newdb->keys = aux.keys;
2623	        newdb->expires = aux.expires;
2624	        newdb->subexpires = aux.subexpires;
2625	        newdb->stream_idmp_keys = aux.stream_idmp_keys;
2626	        newdb->avg_ttl = aux.avg_ttl;
2627	        newdb->expires_cursor = aux.expires_cursor;
2628	
2629	        /* Now we need to handle clients blocked on lists: as an effect
2630	         * of swapping the two DBs, a client that was waiting for list
2631	         * X in a given DB, may now actually be unblocked if X happens
2632	         * to exist in the new version of the DB, after the swap.
2633	         *
2634	         * However normally we only do this check for efficiency reasons
2635	         * in dbAdd() when a list is created. So here we need to rescan
2636	         * the list of clients blocked on lists and signal lists as ready
2637	         * if needed. */
2638	        scanDatabaseForReadyKeys(activedb);
2639	    }
2640	
2641	    trackingInvalidateKeysOnFlush(1);
2642	    flushSlaveKeysWithExpireList();
2643	}
