2710	/* Like setExpire(), but accepts an optional `keyLink` to save lookup */
2711	kvobj *setExpireByLink(client *c, redisDb *db, sds key, long long when, dictEntryLink keyLink) {
2712	    /* Reuse the sds from the main dict in the expire dict */
2713	    int slot = getKeySlot(key);
2714	    size_t oldsize = 0;
2715	    if (!keyLink) {
2716	        keyLink = kvstoreDictFindLink(db->keys, slot, key, NULL);
2717	        serverAssert(keyLink != NULL);
2718	    }
2719	    kvobj *kv = dictGetKV(*keyLink);
2720	    long long old_when = kvobjGetExpire(kv);
2721	
2722	    if (old_when != -1) { /* old expire */
2723	        kvobj *kvnew = kvobjSetExpire(kv, when); /* release kv if reallocated */
2724	        /* Val already had an expire field, so it was not reallocated. */
2725	        serverAssert(kv == kvnew);
2726	    } else { /* No old expire */
2727	        if (server.memory_tracking_enabled)
2728	            oldsize = kvobjAllocSize(kv);
2729	        uint64_t subexpiry = EB_EXPIRE_TIME_INVALID;
2730	        /* If hash with HFEs, take care to remove from global HFE DS before attempting
2731	         * to manipulate and maybe free kv object */
2732	        if (kv->type == OBJ_HASH)
2733	            subexpiry = estoreRemove(db->subexpires, slot, kv);
2734	
2735	        kvobj *kvnew = kvobjSetExpire(kv, when); /* release kv if reallocated */
2736	        /* if kvobj was reallocated, update dict */
2737	        if (kv != kvnew) {
2738	            kvstoreDictSetAtLink(db->keys, slot, kvnew, &keyLink, 0);
2739	            if (server.memory_tracking_enabled)
2740	                updateSlotAllocSize(db, slot, kvnew, oldsize, kvobjAllocSize(kvnew));
2741	            kv = kvnew;
2742	        }
2743	        /* Now add to expires */
2744	        dictEntry *de = kvstoreDictAddRaw(db->expires, slot, kv, NULL);
2745	        serverAssert(de != NULL);
2746	
2747	        if (subexpiry != EB_EXPIRE_TIME_INVALID)
2748	            estoreAdd(db->subexpires, slot, kv, subexpiry);
2749	    }
2750	
2751	    int writable_slave = server.masterhost && server.repl_slave_ro == 0;
2752	    if (c && writable_slave && !(c->flags & CLIENT_MASTER))
2753	        rememberSlaveKeyWithExpire(db,key);
2754	    return kv;
2755	}
