2835	/* Propagate an implicit key deletion into replicas and the AOF file.
2836	 * When a key was deleted in the master by eviction, expiration or a similar
2837	 * mechanism a DEL/UNLINK operation for this key is sent
2838	 * to all the replicas and the AOF file if enabled.
2839	 *
2840	 * This way the key deletion is centralized in one place, and since both
2841	 * AOF and the replication link guarantee operation ordering, everything
2842	 * will be consistent even if we allow write operations against deleted
2843	 * keys.
2844	 *
2845	 * This function may be called from:
2846	 * 1. Within call(): Example: Lazy-expire on key access.
2847	 *    In this case the caller doesn't have to do anything
2848	 *    because call() handles server.also_propagate(); or
2849	 * 2. Outside of call(): Example: Active-expire, eviction, slot ownership changed.
2850	 *    In this the caller must remember to call
2851	 *    postExecutionUnitOperations, preferably just after a
2852	 *    single deletion batch, so that DEL/UNLINK will NOT be wrapped
2853	 *    in MULTI/EXEC */
2854	void propagateDeletion(redisDb *db, robj *key, int lazy) {
2855	    robj *argv[2];
2856	
2857	    argv[0] = lazy ? shared.unlink : shared.del;
2858	    argv[1] = key;
2859	    incrRefCount(argv[0]);
2860	    incrRefCount(argv[1]);
2861	
2862	    /* If the master decided to delete a key we must propagate it to replicas no matter what.
2863	     * Even if module executed a command without asking for propagation. */
2864	    int prev_replication_allowed = server.replication_allowed;
2865	    server.replication_allowed = 1;
2866	    alsoPropagate(db->id,argv,2,PROPAGATE_AOF|PROPAGATE_REPL);
2867	    server.replication_allowed = prev_replication_allowed;
2868	
2869	    decrRefCount(argv[0]);
2870	    decrRefCount(argv[1]);
2871	}
