40	/* The setGenericCommand() function implements the SET operation with different
41	 * options and variants. This function is called in order to implement the
42	 * following commands: SET, SETEX, PSETEX, SETNX, GETSET.
43	 *
44	 * 'flags' changes the behavior of the command (NX, XX, GET, IFEQ, IFNE, IFDEQ
45	 * or IFDNE - see below).
46	 *
47	 * 'expire' represents an expire to set in form of a Redis object as passed
48	 * by the user. It is interpreted according to the specified 'unit'.
49	 *
50	 * 'match_value' is a value to check against if any of IFEQ/IFNE/IFDEQ/IFDNE is
51	 * present.
52	 *
53	 * 'ok_reply' and 'abort_reply' is what the function will reply to the client
54	 * if the operation is performed, or when it is not because of NX or
55	 * XX flags.
56	 *
57	 * If ok_reply is NULL "+OK" is used.
58	 * If abort_reply is NULL, "$-1" is used. */
59	
60	#define OBJ_NO_FLAGS 0
61	#define OBJ_SET_NX (1<<0)          /* Set if key not exists. */
62	#define OBJ_SET_XX (1<<1)          /* Set if key exists. */
63	#define OBJ_EX (1<<2)              /* Set if time in seconds is given */
64	#define OBJ_PX (1<<3)              /* Set if time in ms in given */
65	#define OBJ_KEEPTTL (1<<4)         /* Set and keep the ttl */
66	#define OBJ_SET_GET (1<<5)         /* Set if want to get key before set */
67	#define OBJ_EXAT (1<<6)            /* Set if timestamp in second is given */
68	#define OBJ_PXAT (1<<7)            /* Set if timestamp in ms is given */
69	#define OBJ_PERSIST (1<<8)         /* Set if we need to remove the ttl */
70	#define OBJ_SET_IFEQ (1<<9)        /* Set if value equals match value */
71	#define OBJ_SET_IFNE (1<<10)       /* Set if value does not equal match value */
72	#define OBJ_SET_IFDEQ (1<<11)      /* Set if current digest equals match digest */
73	#define OBJ_SET_IFDNE (1<<12)      /* Set if current digest does not equal match digest */
74	
75	/* Forward declaration */
76	static int getExpireMillisecondsOrReply(client *c, robj *expire, int relative_ttl, int unit, long long *milliseconds);
77	
78	/* Generic SET command family (SET, SETEX, PSETEX, SETNX)
79	 *
80	 * Arguments:
81	 *   valref: A pointer to the robj to be set. This argument may be updated by the function.
82	 *           The object is expected to have a refcount of 1, allowing its ownership to be
83	 *           transferred directly to the database to avoid making a copy. If needed, the
84	 *           function will replace *valref with a new allocation and increment its refcount
85	 *           so that both the database and the caller maintain valid references.
86	 */
87	void setGenericCommand(client *c, int flags, robj *key, robj **valref, robj *expire,
88	                       int unit, robj *match_value, robj *ok_reply, robj *abort_reply)
89	{
90	    long long milliseconds = 0; /* initialized to avoid any harmless warning */
91	    int found = 0;
92	    int setkey_flags = 0;
93	    int relative_ttl = (flags & (OBJ_EX|OBJ_PX)) != 0; /* EX/PX are relative; EXAT/PXAT are absolute. */
94	
95	    if (expire && getExpireMillisecondsOrReply(c, expire, relative_ttl, unit, &milliseconds) != C_OK) {
96	        return;
97	    }
98	
99	    if (flags & OBJ_SET_GET) {
100	        if (getGenericCommand(c) == C_ERR) return;
101	    }
102	
103	    dictEntryLink link = NULL;
104	    found = (lookupKeyWriteWithLink(c->db,key,&link) != NULL);
105	
106	    if ((flags & OBJ_SET_NX && found) ||
107	        (flags & (OBJ_SET_XX | OBJ_SET_IFEQ | OBJ_SET_IFDEQ) && !found))
108	    {
109	        if (!(flags & OBJ_SET_GET)) {
110	            addReply(c, abort_reply ? abort_reply : shared.null[c->resp]);
111	        }
112	        return;
113	    }
114	
115	    /* Handle conditional set operations - only set if key is found and condition
116	     * is met - otherwise return nil. */
117	    if (found && (flags & (OBJ_SET_IFEQ | OBJ_SET_IFNE | OBJ_SET_IFDEQ | OBJ_SET_IFDNE))) {
118	        kvobj *current = lookupKeyRead(c->db, key);
119	        if (checkType(c, current, OBJ_STRING)) {
120	            return;
121	        }
122	
123	        if (flags & OBJ_SET_IFEQ || flags & OBJ_SET_IFNE) {
124	            robj *current_decoded = getDecodedObject(current);
125	            int condition = (flags & OBJ_SET_IFEQ) ?
126	                            sdscmp(current_decoded->ptr, match_value->ptr) == 0 :
127	                            sdscmp(current_decoded->ptr, match_value->ptr) != 0;
128	            decrRefCount(current_decoded);
129	            if (!condition) {
130	                if (!(flags & OBJ_SET_GET)) {
131	                    addReply(c, abort_reply ? abort_reply : shared.null[c->resp]);
132	                }
133	                return;
134	            }
135	        } else if (flags & OBJ_SET_IFDEQ || flags & OBJ_SET_IFDNE) {
136	            if (validateHexDigest(c, match_value->ptr) != C_OK)
137	                return;
138	
139	            sds current_digest = stringDigest(current);
140	            int condition = flags & OBJ_SET_IFDEQ ?
141	                            strcasecmp(current_digest, match_value->ptr) == 0 :
142	                            strcasecmp(current_digest, match_value->ptr) != 0;
143	            sdsfree(current_digest);
144	            if (!condition) {
145	                if (!(flags & OBJ_SET_GET)) {
146	                    addReply(c, abort_reply ? abort_reply : shared.null[c->resp]);
147	                }
148	                return;
149	            }
150	        }
151	    }
152	
153	    /* If the expire time is already elapsed, we don't need to add the key,
154	     * but we still need to update the stats, and we also need to delete the
155	     * key if it exists.
156	     *
157	     * From stats perspective, we behave as if we inserted a new key (possibly
158	     * an overwrite) and later expired it, but from the per-key KSN observability,
159	     * we reflect what we've actually done in the db (deletion of old key, and
160	     * no insertion of new one), so we don't confuse modules. */
161	    if (expire && checkAlreadyExpired(milliseconds)) {
162	        if (found) {
163	            dbDelete(c->db, key);
164	            robj *aux = server.lazyfree_lazy_server_del ? shared.unlink : shared.del;
165	            rewriteClientCommandVector(c, 2, aux, key);
166	            keyModified(c, c->db, key, NULL, 1);
167	            notifyKeyspaceEvent(NOTIFY_GENERIC, "del", key, c->db->id);
168	            server.dirty++;
169	        }
170	        server.stat_expiredkeys++;
171	        if (!(flags & OBJ_SET_GET)) {
172	            addReply(c, ok_reply ? ok_reply : shared.ok);
173	        }
174	        return;
175	    }
176	
177	    /* When expire is not NULL, we avoid deleting the TTL so it can be updated later instead of being deleted and then created again. */
178	    setkey_flags |= ((flags & OBJ_KEEPTTL) || expire) ? SETKEY_KEEPTTL : 0;
179	    setkey_flags |= found ? SETKEY_ALREADY_EXIST : SETKEY_DOESNT_EXIST;
180	
181	    setKeyByLink(c, c->db, key, valref, setkey_flags, &link);
182	    /* If there's an expiration, setExpireByLink may reallocate the object.
183	     * We must update valref to reflect the new object if that happens. */
184	    if (expire) *valref = setExpireByLink(c, c->db, key->ptr, milliseconds, link);
185	    /* The client still holds a reference to the original object via c->argv[i],
186	     * and will call decrRefCount() at the end of call(). We increment the refcount
187	     * from 1 to 2 to ensure both DB and client have valid references. */
188	    incrRefCount(*valref); /* 1->2 */
189	
190	    server.dirty++;
191	    notifyKeyspaceEvent(NOTIFY_STRING,"set",key,c->db->id);
192	
193	    if (expire) {
194	        /* Propagate as SET Key Value PXAT millisecond-timestamp if there is
195	         * EX/PX/EXAT flag. */
196	        if (!(flags & OBJ_PXAT)) {
197	            robj *milliseconds_obj = createStringObjectFromLongLong(milliseconds);
198	            /* If command is exactly "SET key value EX/PX/EXAT ttl", we can just
199	             * replace the expire type and value in-place. Otherwise, we need to
200	             * rewrite the entire command to strip extra flags (NX, XX, GET, etc). */
201	            if ((c->cmd->proc == setCommand) && c->argc == 5) {
202	                rewriteClientCommandArgument(c, 3, shared.pxat);
203	                rewriteClientCommandArgument(c, 4, milliseconds_obj);
204	            } else {
205	                rewriteClientCommandVector(c, 5, shared.set, key, *valref, shared.pxat, milliseconds_obj);
206	            }
207	            decrRefCount(milliseconds_obj);
208	        }
209	        notifyKeyspaceEvent(NOTIFY_GENERIC,"expire",key,c->db->id);
210	    }
211	
212	    if (!(flags & OBJ_SET_GET)) {
213	        addReply(c, ok_reply ? ok_reply : shared.ok);
214	    }
215	
216	    /* Propagate without the GET argument (Isn't needed if we had expire since in that case we completely re-written the command argv) */
217	    if ((flags & OBJ_SET_GET) && !expire) {
218	        for (int j = c->argc - 1; j >= 3; j--) {
219	            char *a = c->argv[j]->ptr;
220	            /* Skip GET which may be repeated multiple times. */
221	            if ((a[0] == 'g' || a[0] == 'G') &&
222	                (a[1] == 'e' || a[1] == 'E') &&
223	                (a[2] == 't' || a[2] == 'T') && a[3] == '\0')
224	            {
225	                rewriteClientCommandArgument(c, j, NULL);
226	            }
227	        }
228	    }
229	}
230	
231	/*
232	 * Extract the `expire` argument of a given command as an absolute timestamp in milliseconds.
233	 *
234	 * "client" is the client that sent the `expire` argument.
235	 * "expire" is the `expire` argument to be extracted.
236	 * "relative_ttl" is true when the value is a relative TTL (EX/PX),
237	 *                false when it is an absolute timestamp (EXAT/PXAT).
238	 * "unit" is the original unit of the given `expire` argument (e.g. UNIT_SECONDS).
239	 * "milliseconds" is output argument.
240	 *
241	 * If return C_OK, "milliseconds" output argument will be set to the resulting absolute timestamp.
242	 * If return C_ERR, an error reply has been added to the given client.
243	 */
244	static int getExpireMillisecondsOrReply(client *c, robj *expire, int relative_ttl, int unit, long long *milliseconds) {
245	    int ret = getLongLongFromObjectOrReply(c, expire, milliseconds, NULL);
246	    if (ret != C_OK) {
247	        return ret;
248	    }
249	
250	    if (*milliseconds <= 0 || (unit == UNIT_SECONDS && *milliseconds > LLONG_MAX / 1000)) {
251	        /* Negative value provided or multiplication is gonna overflow. */
252	        addReplyErrorExpireTime(c);
253	        return C_ERR;
254	    }
255	
256	    if (unit == UNIT_SECONDS) *milliseconds *= 1000;
257	
258	    if (relative_ttl) {
259	        *milliseconds += commandTimeSnapshot();
260	    }
261	
262	    if (*milliseconds <= 0) {
263	        /* Overflow detected. */
264	        addReplyErrorExpireTime(c);
265	        return C_ERR;
266	    }
267	
268	    return C_OK;
269	}
270	
271	#define COMMAND_GET 0
272	#define COMMAND_SET 1
273	#define COMMAND_MSETEX 2
274	
275	/* Extended string command arguments structure */
276	typedef struct {
277	    int flags;
278	    int unit;
279	    int expire_pos;  /* Position of EX/PX flag for replication rewriting */
280	    robj *expire;
281	    robj *match_value; /* For IFEQ/IFNE/IFDEQ/IFDNE conditions */
282	} extendedStringArgs;
283	
284	/*
285	 * The parseExtendedStringArgumentsOrReply() function performs the common validation for extended
286	 * string arguments used in SET, GET and MSETEX commands.
287	 *
288	 * Get specific commands - PERSIST/DEL
289	 * Set specific commands - XX/NX/GET/IFEQ/IFNE/IFDEQ/IFDNE
290	 * Common commands - EX/EXAT/PX/PXAT/KEEPTTL
291	 *
292	 * Function takes pointers to client, start_pos for where to begin parsing, extendedStringArgs
293	 * structure to populate, and command_type which can be COMMAND_GET, COMMAND_SET, or COMMAND_MSETEX.
294	 *
295	 * If there are any syntax violations C_ERR is returned else C_OK is returned.
296	 *
297	 * The args structure is updated upon parsing the arguments. Unit and expire are updated if there are any
298	 * EX/EXAT/PX/PXAT arguments. Unit is updated to millisecond if PX/PXAT is set.
299	 * match_value is updated if any of IFEQ/IFNE/IFDEQ/IFDNE is set.
300	 */

