100	                                                   we do extra efforts. */
101	
102	#define HFE_DB_BASE_ACTIVE_EXPIRE_FIELDS_PER_SEC 10000
103	
104	/* Data used by the expire dict scan callback. */
105	typedef struct {
106	    redisDb *db;
107	    long long now;
108	    unsigned long sampled; /* num keys checked */
109	    unsigned long expired; /* num keys expired */
110	    long long ttl_sum; /* sum of ttl for key with ttl not yet expired */
111	    int ttl_samples; /* num keys with ttl not yet expired */
112	} expireScanData;
113	
114	void expireScanCallback(void *privdata, const dictEntry *de, dictEntryLink plink) {
115	    UNUSED(plink);
116	    kvobj *kv = dictGetKV(de);
117	    expireScanData *data = privdata;
118	    long long ttl  = kvobjGetExpire(kv) - data->now;
119	    if (activeExpireCycleTryExpire(data->db, kv, data->now)) {
120	        data->expired++;
121	    }
122	    if (ttl > 0) {
123	        /* We want the average TTL of keys yet not expired. */
124	        data->ttl_sum += ttl;
125	        data->ttl_samples++;
126	    }
127	    data->sampled++;
128	}
129	
130	static inline int expirySamplingShouldSkipDict(dict *d, int didx) {
131	    long long numkeys = dictSize(d);
132	    unsigned long buckets = dictBuckets(d);
133	    /* When there are less than 1% filled buckets, sampling the key
134	     * space is expensive, so stop here waiting for better times...
135	     * The dictionary will be resized asap. */
136	    if (buckets > DICT_HT_INITIAL_SIZE && (numkeys * 100/buckets < 1)) {
137	        return 1;
138	    }
139	
140	    /* During atomic slot migration, keys that are being imported are in an
141	     * intermediate state. we cannot expire them and therefore skip them. */
142	    if (!clusterCanAccessKeysInSlot(didx)) return 1;
143	
144	    return 0;
145	}
146	
147	/* SubexpireCtx passed to activeSubexpiresCb() */
148	typedef struct SubexpireCtx {
149	    uint32_t fieldsToExpireQuota;
150	    redisDb *db;
151	    int slot;
152	} SubexpireCtx;
153	
154	/*
155	 * Active sub-expiration callback
156	 *
157	 * Called by activeSubexpires() for each key registered in the subexpires DB
158	 * with an expiration-time on its "elements"  that are less than or equal current
159	 * time.
160	 *
161	 * This callback performs the following actions for each hash:
162	 * - Delete expired fields as by calling ebExpire(hash)
163	 * - If afterward there are future fields to expire, it will update the hash in
164	 *   HFE DB with the next hash-field minimum expiration time by returning
165	 *   ACT_UPDATE_EXP_ITEM.
166	 * - If the hash has no more fields to expire, it is removed from the HFE DB
167	 *   by returning ACT_REMOVE_EXP_ITEM.
168	 * - If hash has no more fields afterward, it will remove the hash from keyspace.
169	 */
170	static ExpireAction activeSubexpiresCb(eItem item, void *ctx) {
171	    SubexpireCtx *subexCtx = ctx;
172	
173	    /* If no more quota left for this callback, stop */
174	    if (subexCtx->fieldsToExpireQuota == 0)
175	        return ACT_STOP_ACTIVE_EXP;
176	
177	    kvobj *kv = (kvobj *) item;
178	
179	    /* currently we only support hash type sub-expire */
180	    assert(kv->type == OBJ_HASH);
181	    uint64_t nextExpTime = hashTypeExpire(subexCtx->db, kv, &subexCtx->fieldsToExpireQuota, 0, 1);
182	
183	    /* If hash has no more fields to expire or got deleted, indicate
184	     * to remove it from HFE DB to the caller ebExpire() */
185	    if (nextExpTime == EB_EXPIRE_TIME_INVALID || nextExpTime == 0) {
186	        return ACT_REMOVE_EXP_ITEM;
187	    } else {
188	        /* Hash has more fields to expire. Update next expiration time of the hash
189	         * and indicate to add it back to global HFE DS */
190	        ebSetMetaExpTime(hashGetExpireMeta(item), nextExpTime);
191	        return ACT_UPDATE_EXP_ITEM;
192	    }
193	}
194	
195	/* DB active expire and update hashes with time-expiration on fields.
196	 *
197	 * The callback function activeSubexpiresCb() is invoked for each hash registered
198	 * in the subexpires DB with an expiration-time less than or equal to the
199	 * current time. This callback performs the following actions for each hash:
200	 * - If the hash has one or more fields to expire, it will delete those fields.
201	 * - If there are more fields to expire, it will update the hash with the next
202	 *   expiration time in subexpires DB.
203	 * - If the hash has no more fields to expire, it is removed from the subexpires DB.
204	 * - If the hash has no more fields, it is removed from the main DB.
205	 *
206	 * Returns number of fields active-expired.
207	 */
208	uint64_t activeSubexpires(redisDb *db, int slot, uint32_t maxFieldsToExpire) {
209	    SubexpireCtx ctx = { .db = db, .fieldsToExpireQuota = maxFieldsToExpire, .slot = slot };
210	    ExpireInfo info = {
211	            .maxToExpire = UINT64_MAX, /* Only maxFieldsToExpire play a role */
212	            .onExpireItem = activeSubexpiresCb,
213	            .ctx = &ctx,
214	            .now = commandTimeSnapshot(),
215	            .itemsExpired = 0};
216	
217	    estoreActiveExpire(db->subexpires, slot, &info);
218	
219	    /* Return number of fields active-expired */
220	    return maxFieldsToExpire - ctx.fieldsToExpireQuota;
221	}
222	
223	/* Active expiration Cycle for hash-fields.
224	 *
225	 * Note that releasing fields is expected to be more predictable and rewarding
226	 * than releasing keys because it is stored in `ebuckets` DS which optimized for
227	 * active expiration and in addition the deletion of fields is simple to handle. */
228	static inline void activeSubexpiresCycle(int type) {
229	    /* Remember current db across calls */
230	    static unsigned int currentDb = 0;
231	    static int currentSlot = -1;
232	
233	    /* Tracks the count of fields actively expired for the current database.
234	     * This count continues as long as it fails to actively expire all expired
235	     * fields of currentDb, indicating a possible need to adjust the value of
236	     * maxToExpire. */
237	    static uint64_t activeExpirySequence = 0;
238	    /* Threshold for adjusting maxToExpire */
239	    const uint32_t EXPIRED_FIELDS_TH = 1000000;
240	
241	    redisDb *db = server.db + currentDb;
242	
243	    /* If db is empty, move to next db and return */
244	    if (estoreIsEmpty(db->subexpires)) {
245	        activeExpirySequence = 0;
246	        currentDb = (currentDb + 1) % server.dbnum;
247	        return;
248	    }
249	    if (currentSlot == -1)
250	        currentSlot = estoreGetFirstNonEmptyBucket(db->subexpires);
251	
252	    /* During atomic slot migration, keys that are being imported are in an
253	     * intermediate state. We cannot expire them and therefore skip them. */
254	    if (!clusterCanAccessKeysInSlot(currentSlot)) {
255	        /* Move to next non-empty subexpires slot */
256	        currentSlot = estoreGetNextNonEmptyBucket(db->subexpires, currentSlot);
257	        if (currentSlot == -1)
258	            currentDb = (currentDb + 1) % server.dbnum; /* Move to next db */
259	        return;
260	    }
261	
262	    /* Maximum number of fields to actively expire on a single call */
263	    uint32_t maxToExpire = HFE_DB_BASE_ACTIVE_EXPIRE_FIELDS_PER_SEC / server.hz;
264	
265	    /* If running for a while and didn't manage to active-expire all expired fields of
266	     * currentDb (i.e. activeExpirySequence becomes significant) then adjust maxToExpire */
267	    if ((activeExpirySequence > EXPIRED_FIELDS_TH) && (type == ACTIVE_EXPIRE_CYCLE_SLOW)) {
268	        /* maxToExpire is multiplied by a factor between 1 and 32, proportional to
269	         * the number of times activeExpirySequence exceeded EXPIRED_FIELDS_TH */
270	        uint64_t factor = activeExpirySequence / EXPIRED_FIELDS_TH;
271	        maxToExpire *= (factor<32) ? factor : 32;
272	    }
273	
274	    if (activeSubexpires(db, currentSlot, maxToExpire) == maxToExpire) {
275	        /* active-expire reached maxToExpire limit */
276	        activeExpirySequence += maxToExpire;
277	    } else {
278	        /* Managed to active-expire all expired fields of currentDb */
279	        activeExpirySequence = 0;
280	        /* Move to next non-empty subexpires slot */
281	        currentSlot = estoreGetNextNonEmptyBucket(db->subexpires, currentSlot);
282	        if (currentSlot == -1)
283	            currentDb = (currentDb + 1) % server.dbnum;
284	    }
285	}
286	
287	void activeExpireCycle(int type) {
288	    /* Adjust the running parameters according to the configured expire
289	     * effort. The default effort is 1, and the maximum configurable effort
290	     * is 10. */
