         * bits set in the value bitmap. */
        int dbid = 0;
        while(dbids && dbid < server.dbnum) {
            if ((dbids & 1) != 0) {
                redisDb *db = server.db+dbid;
                kvobj *kv = dbFindExpires(db, keyname);
                int expired = kv && activeExpireCycleTryExpire(server.db+dbid, kv, start);

